var CURRENT_USER = null;

async function _sha256(str){
  var buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
}

async function doLogin(){
  var email = (document.getElementById('iqvia-login-email').value||'').trim().toLowerCase();
  var pwd   = document.getElementById('iqvia-login-pwd').value||'';
  var btn   = document.getElementById('iqvia-login-btn');
  var err   = document.getElementById('iqvia-login-error');
  if(!email||!pwd){ showAuthError('Please enter email and password.'); return; }
  btn.disabled = true; btn.textContent = 'Signing in...';
  err.classList.remove('show');
  try{
    var hash = await _sha256(email+':'+pwd+':ZETA2026INTEL');
    var user = ZETA_USERS[email];
    if(!user||user.hash!==hash){ showAuthError('Invalid email or password.'); btn.disabled=false; btn.textContent='Sign In'; return; }
    localStorage.setItem('zeta_session', JSON.stringify({email:email,name:user.name,role:user.role,expires:Date.now()+8*3600*1000}));
    CURRENT_USER = user;
    document.getElementById('iqvia-zeta-login').classList.add('hidden');
    document.getElementById('iqvia-badge-name').textContent = user.name;
    document.getElementById('iqvia-badge-role').textContent = user.role;
    document.getElementById('iqvia-user-badge').style.display='flex';
    btn.disabled=false; btn.textContent='Sign In';
    startDashboard();
    fetchNotifications();
  }catch(e){ showAuthError('Login error. Try again.'); btn.disabled=false; btn.textContent='Sign In'; }
}

function showAuthError(msg){
  var e=document.getElementById('iqvia-login-error');
  e.textContent=msg; e.classList.add('show');
}

function doLogout(){
  localStorage.removeItem('zeta_session');
  CURRENT_USER=null;
  location.reload();
}

document.addEventListener('keydown',function(e){
  if(e.key==='Enter'&&!document.getElementById('iqvia-zeta-login').classList.contains('hidden'))doLogin();
});

function checkSession(){
  try{
    var s=JSON.parse(localStorage.getItem('zeta_session')||'null');
    if(s&&s.expires>Date.now()){
      var u=ZETA_USERS[s.email];
      if(u){
        CURRENT_USER=u;
        document.getElementById('iqvia-zeta-login').classList.add('hidden');
        document.getElementById('iqvia-badge-name').textContent=u.name;
        document.getElementById('iqvia-badge-role').textContent=u.role;
        document.getElementById('iqvia-user-badge').style.display='flex';
        return true;
      }
    }
  }catch(e){}
  return false;
}

function applyUserFilter(){
  if(!CURRENT_USER)return;
  var bu=CURRENT_USER.bu, ln=CURRENT_USER.lines, dm=CURRENT_USER.dm1s, pr=CURRENT_USER.prods;
  if(!bu&&!ln&&!dm&&!pr){ window.USER_VISIBLE=null; return; } // Admin — full access

  // MARKET SCOPE: filter only by dm1s (the markets this user manages).
  // bu and lines are Zeta-internal org fields — they are only populated on Zeta's own
  // product rows, so using them as row filters would exclude ALL competitor data.
  // dm1s is the correct scope boundary for BU Managers.
  var aDM = dm ? new Set(dm.map(function(v){return LOOKUPS.dm1s.indexOf(v);}).filter(function(i){return i>=0;})) : null;

  // If no dm1s defined at all (edge case), fall back to bu-based scope
  var aBU_fallback = (!dm && bu)
    ? new Set(bu.map(function(v){return LOOKUPS.bus.indexOf(v);}).filter(function(i){return i>=0;}))
    : null;

  var out=[];
  // Track exactly which dimension values appear in the filtered data
  var visCorp=new Set(), visProd=new Set(), visAtc4=new Set();
  var visDm1=new Set(), visDm2=new Set(), visLine=new Set(), visBu=new Set();
  for(var i=0;i<flat.length;i+=10){
    if(aDM           && !aDM.has(flat[i+D1I]))           continue; // primary: market scope
    if(aBU_fallback  && !aBU_fallback.has(flat[i+BUCI])) continue; // fallback: bu only
    out.push(flat[i],flat[i+1],flat[i+2],flat[i+3],flat[i+4],flat[i+5],flat[i+6],flat[i+7],flat[i+8],flat[i+9]);
    visCorp.add(flat[i]);
    visProd.add(flat[i+1]);
    visAtc4.add(flat[i+3]);
    visDm1.add(flat[i+4]);
    visDm2.add(flat[i+5]);
    visLine.add(flat[i+8]);
    visBu.add(flat[i+9]);
  }
  flat=out;
  // Store visible sets — used by populateFilters() to restrict slicer options
  window.USER_VISIBLE = {corp:visCorp, prod:visProd, atc4:visAtc4, dm1:visDm1, dm2:visDm2, line:visLine, bu:visBu};
  console.log('Filtered flat for '+CURRENT_USER.name+': '+flat.length/10+' rows | Corps:'+visCorp.size+' DM1:'+visDm1.size+' DM2:'+visDm2.size+' ATC4:'+visAtc4.size);
}

