// ===================== ZETA MARKET ANALYSIS =====================
function renderZetaMarket() {
  const SEC        = 's-zeta-market';
  const curPidxs   = getPeriodIndices(STATE.timeRange);
  const prevPidxs  = getPrevPeriodIndices(STATE.timeRange);
  const ml         = STATE.metric==='lcv'?'LCV':'SU';
  const rangeLabel = {mat:'MAT',ytd:'YTD',curr:'Month',all:'All','3m':'3M','6m':'6M'}[STATE.timeRange]||STATE.timeRange;

  // ── Dual filters ─────────────────────────────────────────────────────────────
  // zetaFilter : Zeta corp + BU / Line / DM1 / ATC4 / DM2 active selections
  // mktFilter  : all corps + DM1 / ATC4 / DM2 / Corp only (BU & Line are
  //              Zeta-internal — applying them to competitors would zero-out
  //              market totals and make share calculations meaningless)
  const _hasBu   = STATE.fBuSel.size>0,  _hasLine = STATE.fLineSel.size>0;
  const _hasDm1  = STATE.fDm1Sel.size>0, _hasAtc4 = STATE.fAtc4Sel.size>0;
  const _hasDm2  = STATE.fDm2Sel.size>0, _hasCorp = STATE.fCorpSel.size>0;

  const zetaFilter = (_hasBu||_hasLine||_hasDm1||_hasAtc4||_hasDm2)
    ? (c,p,t,a,d1,d2,ln,bu)=>{
        if(c!==ZETA_IDX) return false;
        if(_hasBu   && !STATE.fBuSel.has(bu))   return false;
        if(_hasLine && !STATE.fLineSel.has(ln))  return false;
        if(_hasDm1  && !STATE.fDm1Sel.has(d1))  return false;
        if(_hasAtc4 && !STATE.fAtc4Sel.has(a))  return false;
        if(_hasDm2  && !STATE.fDm2Sel.has(d2))  return false;
        return true;
      }
    : c=>c===ZETA_IDX;

  const mktFilter = (_hasDm1||_hasAtc4||_hasDm2||_hasCorp)
    ? (c,p,t,a,d1,d2)=>{
        if(_hasCorp && !STATE.fCorpSel.has(c))  return false;
        if(_hasDm1  && !STATE.fDm1Sel.has(d1))  return false;
        if(_hasAtc4 && !STATE.fAtc4Sel.has(a))  return false;
        if(_hasDm2  && !STATE.fDm2Sel.has(d2))  return false;
        return true;
      }
    : null;

  // Active filter context label for section header
  const buName   = _hasBu   ? [...STATE.fBuSel].map(i=>LOOKUPS.bus[i]||'BU '+i).join(', ')   : '';
  const lineName = _hasLine ? [...STATE.fLineSel].map(i=>LOOKUPS.lines[i]||'Line '+i).join(', ') : '';
  const ctxLabel = buName ? ' · BU: '+buName : lineName ? ' · Line: '+lineName : '';

  // ── Data Collection ──────────────────────────────────────────────────────────
  const zetaDm1Cur   = aggBy(D1I, zetaFilter, curPidxs);
  const zetaDm1Prev  = aggBy(D1I, zetaFilter, prevPidxs);
  const zetaAtc4Cur  = aggBy(AI,  zetaFilter, curPidxs);
  const zetaAtc4Prev = aggBy(AI,  zetaFilter, prevPidxs);
  const mktDm1Cur    = aggBy(D1I, mktFilter,  curPidxs);
  const mktDm1Prev   = aggBy(D1I, mktFilter,  prevPidxs);
  const mktAtc4Cur   = aggBy(AI,  mktFilter,  curPidxs);

  // ── KPI Totals ───────────────────────────────────────────────────────────────
  const totalZetaLcv  = [...zetaDm1Cur.values()].reduce((s,v)=>s+MV(v),0);
  const totalZetaPrev = [...zetaDm1Prev.values()].reduce((s,v)=>s+MV(v),0);
  const totalMktLcv   = [...mktDm1Cur.values()].reduce((s,v)=>s+MV(v),0);
  const totalMktPrev  = [...mktDm1Prev.values()].reduce((s,v)=>s+MV(v),0);
  const avgShare      = totalMktLcv>0 ? totalZetaLcv/totalMktLcv : 0;
  const prevAvgShare  = totalMktPrev>0 ? totalZetaPrev/totalMktPrev : 0;
  const zetaGrOvr     = growth(totalZetaLcv, totalZetaPrev);
  const mktGrOvr      = growth(totalMktLcv,  totalMktPrev);

  // ── Enhanced DM1 List ────────────────────────────────────────────────────────
  const dm1List = [...zetaDm1Cur.entries()].map(([d,v])=>{
    const pv      = zetaDm1Prev.get(d)||{lcv:0,su:0};
    const mkt     = mktDm1Cur.get(d)||{lcv:1,su:1};
    const mktPrev = mktDm1Prev.get(d)||{lcv:0,su:0};
    const lcv=MV(v), prevLcv=MV(pv), mktLcv=MV(mkt), mktPrevLcv=MV(mktPrev);
    const zetaShare  = mktLcv>0  ? lcv/mktLcv : 0;
    const prevShare  = mktPrevLcv>0 ? prevLcv/mktPrevLcv : 0;
    const shareDelta = zetaShare - prevShare;
    const mktGr      = growth(mktLcv, mktPrevLcv);
    const zetaGr     = growth(lcv, prevLcv);
    const rgi        = Math.abs(1+mktGr)>0.005 ? (1+zetaGr)/(1+mktGr) : null;
    const headroom   = (1-zetaShare)*mktLcv;
    return {d, lcv, mktLcv, zetaShare, prevShare, shareDelta, mktGr, zetaGr, rgi, headroom};
  }).sort((a,b)=>b.lcv-a.lcv);

  const outperformN = dm1List.filter(x=>x.rgi!=null&&x.rgi>=1).length;

  // ── Top product per DM1 (Zeta, current period) ──────────────────────────────
  const _dm1ProdMap = new Map(); // dm1 → Map(prod → lcv)
  for(let i=0;i<flat.length;i+=10){
    if(flat[i+CI]!==ZETA_IDX) continue;
    if(!curPidxs.has(flat[i+TI])) continue;
    if(_hasBu   && !STATE.fBuSel.has(flat[i+BUCI]))   continue;
    if(_hasLine && !STATE.fLineSel.has(flat[i+LINEI])) continue;
    if(_hasDm1  && !STATE.fDm1Sel.has(flat[i+D1I]))   continue;
    if(_hasAtc4 && !STATE.fAtc4Sel.has(flat[i+AI]))   continue;
    if(_hasDm2  && !STATE.fDm2Sel.has(flat[i+D2I]))   continue;
    const d1=flat[i+D1I], p=flat[i+PI], lcv=flat[i+LI];
    if(!lcv) continue;
    if(!_dm1ProdMap.has(d1)) _dm1ProdMap.set(d1,new Map());
    const pm=_dm1ProdMap.get(d1);
    pm.set(p,(pm.get(p)||0)+lcv);
  }
  const dm1TopProdName = new Map();
  _dm1ProdMap.forEach((pm,d1)=>{
    const top=[...pm.entries()].sort((a,b)=>b[1]-a[1])[0];
    if(top) dm1TopProdName.set(d1, LOOKUPS.prods[top[0]]||'');
  });

  // ── Dynamic Insights ──────────────────────────────────────────────────────
  const _dn      = d=>(LOOKUPS.dm1s[d]||'Unknown').substring(0,22);
  const starMkts = dm1List.filter(x=>x.rgi!=null&&x.rgi>=1.3&&x.shareDelta>0).slice(0,3);
  const topOpp   = dm1List.filter(x=>x.rgi!=null&&x.rgi>=1&&x.headroom>0&&x.mktGr>=0)
                          .sort((a,b)=>b.headroom-a.headroom).slice(0,3);
  const riskMkts = dm1List.filter(x=>x.rgi!=null&&x.rgi<0.7&&x.shareDelta<0).slice(0,3);
  const ctrCycN  = dm1List.filter(x=>x.mktGr<-0.02&&x.zetaGr>0.02).length;

  const insightHTML=(()=>{
    const b=[];
    // Signal 1 — overall vs market
    const sdPP=((avgShare-prevAvgShare)*100).toFixed(2);
    if(zetaGrOvr>mktGrOvr)
      b.push(`<span style="color:#2fc97e;font-weight:700">📈 Outperforming</span> — Zeta ${fmtGrowth(zetaGrOvr)} vs market ${fmtGrowth(mktGrOvr)}; weighted share ${sdPP>=0?'+':''}${sdPP}pp to <b>${fmtPct(avgShare)}</b>.`);
    else
      b.push(`<span style="color:#e05c5c;font-weight:700">⚠ Lagging market</span> — Zeta ${fmtGrowth(zetaGrOvr)} vs market ${fmtGrowth(mktGrOvr)}; share change ${sdPP>=0?'+':''}${sdPP}pp → <b>${fmtPct(avgShare)}</b>.`);
    // Signal 2 — star markets
    if(starMkts.length>0)
      b.push(`<span style="color:#7ee8a2;font-weight:700">⭐ Star markets</span> — High RGI &amp; share gain: ${starMkts.map(x=>`<b>${_dn(x.d)}</b> · ${dm1TopProdName.get(x.d)||'—'} (RGI ${x.rgi.toFixed(2)}, +${(x.shareDelta*100).toFixed(2)}pp)`).join(' · ')}.`);
    // Signal 3 — top opportunities
    if(topOpp.length>0)
      b.push(`<span style="color:#4c6ef5;font-weight:700">🎯 Opportunity</span> — Growing markets with headroom &amp; RGI≥1: ${topOpp.map(x=>`<b>${_dn(x.d)}</b> · <i>${dm1TopProdName.get(x.d)||'—'}</i> (${fmtLCV(x.headroom)} headroom)`).join(' · ')}.`);
    // Signal 4 — at-risk
    if(riskMkts.length>0)
      b.push(`<span style="color:#e05c5c;font-weight:700">🚨 At-risk</span> — Underperforming &amp; losing share: ${riskMkts.map(x=>`<b>${_dn(x.d)}</b> (RGI ${x.rgi.toFixed(2)}, ${(x.shareDelta*100).toFixed(2)}pp Δ)`).join(' · ')}.`);
    // Signal 5 — counter-cyclical
    if(ctrCycN>0)
      b.push(`<span style="color:#ffb800;font-weight:700">💡 Counter-cyclical</span> — Zeta growing in <b>${ctrCycN}</b> declining market${ctrCycN>1?'s':''} — resilience signal worth flagging to leadership.`);
    // Signal 6 — outperform ratio
    const pct=(outperformN/(dm1List.length||1)*100).toFixed(0);
    b.push(`<span style="color:var(--txt2);font-weight:700">📊 Portfolio coverage</span> — Zeta outperforms market in <b>${outperformN}/${dm1List.length}</b> markets (${pct}%); RGI≥1 threshold.`);
    return `<div class="commentary" style="margin-bottom:16px;border-left:3px solid var(--acc1);padding-left:14px;padding-top:2px;padding-bottom:2px">
      <div style="font-size:10.5px;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.6px;margin-bottom:7px">⚡ Dynamic Insights — ${rangeLabel}${ctxLabel}</div>
      ${b.map(x=>`<p style="font-size:12.5px;line-height:1.6;margin-bottom:4px">${x}</p>`).join('')}
    </div>`;
  })();

  // ── ATC4 Enhanced List ───────────────────────────────────────────────────────
  const atc4List = [...zetaAtc4Cur.entries()].map(([a,v])=>{
    const pv=zetaAtc4Prev.get(a)||{lcv:0,su:0};
    const mkt=mktAtc4Cur.get(a)||{lcv:1,su:1};
    const lcv=MV(v), mktLcv=MV(mkt);
    return {a, lcv, mktLcv, share:mktLcv>0?lcv/mktLcv:0, gr:growth(lcv,MV(pv))};
  }).sort((a,b)=>b.lcv-a.lcv);
  const atc4Total = atc4List.reduce((s,x)=>s+x.lcv,0)||1;

  // ── Share Win/Loss items ─────────────────────────────────────────────────────
  const sorted=([...dm1List]).sort((a,b)=>b.shareDelta-a.shareDelta);
  const wlItems=[...sorted.filter(x=>x.shareDelta>=0).slice(0,5),
                 ...sorted.filter(x=>x.shareDelta<0).sort((a,b)=>a.shareDelta-b.shareDelta).slice(0,5)];

  // ── Bubble datasets ──────────────────────────────────────────────────────────
  // Limit to top 20 markets by LCV to prevent over-clustering
  const bubbleDm1 = dm1List.slice(0, 20);
  const mkBub=x=>({
    x:+(x.mktGr*100).toFixed(2), y:+(x.zetaShare*100).toFixed(2),
    r:Math.max(5,Math.min(26,Math.sqrt(x.mktLcv/(totalMktLcv||1))*110)),
    name:(LOOKUPS.dm1s[x.d]||'').substring(0,20), mktLcv:x.mktLcv,
    rgi:x.rgi, sdelta:x.shareDelta, lcv:x.lcv,
    topProd:dm1TopProdName.get(x.d)||'—' 
  });
  const bubbleDS=[
    {label:'Outperforming (RGI ≥ 1)', data:bubbleDm1.filter(x=>x.rgi==null||x.rgi>=1).map(mkBub),
     backgroundColor:'rgba(47,201,126,.65)',borderColor:'rgba(47,201,126,.9)',borderWidth:1},
    {label:'Underperforming (RGI < 1)',data:bubbleDm1.filter(x=>x.rgi!=null&&x.rgi<1).map(mkBub),
     backgroundColor:'rgba(224,92,92,.65)',borderColor:'rgba(224,92,92,.9)',borderWidth:1}
  ];

  // ── Colour helpers ───────────────────────────────────────────────────────────
  const rgiClr=r=>r==null?'color:var(--txt3)':r>=1.5?'color:#2fc97e':r>=1?'color:#7ee8a2':r>=0.5?'color:#ffb800':'color:#e05c5c';
  const sdClr =d=>d>0?'color:#2fc97e':d<0?'color:#e05c5c':'color:var(--txt3)';
  const kpi=(label,val,sub,card='blue')=>
    `<div class="kpi-card ${card}"><div class="kpi-label">${label}</div>
     <div class="kpi-value">${val}</div><div class="kpi-sub">${sub}</div></div>`;

  // ── HTML ─────────────────────────────────────────────────────────────────────
  const pageHtml=`
  <div class="section-title">🔍 Zeta Market Analysis</div>
  <div class="section-sub">Strategic position · Share evolution · Growth decomposition — ${rangeLabel}${ctxLabel}</div>

  <div class="kpi-grid" style="grid-template-columns:repeat(4,1fr);margin-bottom:16px">
    ${kpi('Zeta Total '+ml, fmtLCV(totalZetaLcv), fmtGrowth(zetaGrOvr)+' vs prior', zetaGrOvr>0?'green':'red')}
    ${kpi('Total Market '+ml, fmtLCV(totalMktLcv), 'Market growth: '+fmtGrowth(mktGrOvr), 'blue')}
    ${(()=>{ const validRgi=dm1List.filter(x=>x.rgi!=null); const avgRgi=validRgi.length?validRgi.reduce((s,x)=>s+x.rgi,0)/validRgi.length:0; const prevRgi=1; return kpi('Avg Portfolio RGI', avgRgi.toFixed(2)+'×', outperformN+' of '+dm1List.length+' mkts RGI≥1', avgRgi>=1.1?'green':avgRgi>=1?'orange':'red'); })()}
    ${kpi('Markets Outperforming', outperformN+' / '+dm1List.length, 'Zeta growth &gt; Market growth (RGI ≥ 1)', outperformN>=dm1List.length/2?'green':'orange')}
  </div>

  ${insightHTML}

  <div class="chart-row cols2">
    <div class="chart-box">
      <div class="chart-box-title">Strategic Position Matrix
        <span class="chart-box-sub">X: Market Growth % &nbsp;·&nbsp; Y: Zeta Share % &nbsp;·&nbsp; Bubble = Market Size</span></div>
      <div style="display:flex;gap:6px;padding:4px 12px 0;font-size:10px;flex-wrap:wrap">
        <span style="background:rgba(47,201,126,.15);color:#2fc97e;padding:2px 8px;border-radius:10px">● Outperforming (RGI ≥ 1)</span>
        <span style="background:rgba(224,92,92,.15);color:#e05c5c;padding:2px 8px;border-radius:10px">● Underperforming (RGI < 1)</span>
      </div>
      <div class="chart-wrap" style="height:380px"><canvas id="ch-zm-bubble"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">Market Share Win / Loss
        <span class="chart-box-sub">Share Δ vs prior period — top gainers &amp; losers</span></div>
      <div class="chart-wrap" style="height:300px"><canvas id="ch-zm-wl"></canvas></div>
    </div>
  </div>

  <div class="tbl-wrap">
    <div class="tbl-head">
      <span class="tbl-head-title">📊 Zeta DM1 Full Performance — ${rangeLabel}</span>
      <span style="font-size:11px;color:var(--txt3);margin-left:10px">RGI = Zeta Growth ÷ Market Growth &nbsp;|&nbsp; Headroom = Remaining Market Potential</span>
    </div>
    <div class="tbl-scroll"><table id="tbl-zm2"><thead><tr>
      <th>#</th><th>Defined Market 1</th>
      <th>Zeta ${ml}</th><th>Market ${ml}</th>
      <th>Share %</th><th>Prior Share</th><th>Share Δ</th>
      <th>Top Product</th><th>Mkt Growth</th><th>Zeta Growth</th><th>RGI</th><th>Headroom</th>
    </tr></thead><tbody>
    ${dm1List.map((x,i)=>`<tr>
      <td><span class="rank-badge ${i<3?'top3':''}">${i+1}</span></td>
      <td style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${LOOKUPS.dm1s[x.d]||''}">${(LOOKUPS.dm1s[x.d]||'').substring(0,26)}</td>
      <td>${fmtLCV(x.lcv)}</td>
      <td>${fmtLCV(x.mktLcv)}</td>
      <td style="font-weight:600">${fmtPct(x.zetaShare)}</td>
      <td style="color:var(--txt3)">${fmtPct(x.prevShare)}</td>
      <td style="${sdClr(x.shareDelta)};font-weight:600">${(x.shareDelta>=0?'+':'')}${(x.shareDelta*100).toFixed(2)}pp</td>
      <td style="font-size:11px;color:var(--acc1);max-width:110px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${dm1TopProdName.get(x.d)||'—'}">${(dm1TopProdName.get(x.d)||'—').substring(0,14)}</td>
      <td>${fmtGrowth(x.mktGr)}</td>
      <td>${fmtGrowth(x.zetaGr)}</td>
      <td style="${rgiClr(x.rgi)};font-weight:700">${x.rgi!=null?x.rgi.toFixed(2):'—'}</td>
      <td style="color:var(--txt2)">${fmtLCV(x.headroom)}</td>
    </tr>`).join('')}
    </tbody></table></div>
  </div>

  <div class="chart-row cols2" style="margin-top:16px">
    <div class="chart-box">
      <div class="chart-box-title">Zeta — ATC4 Portfolio Mix
        <span class="chart-box-sub">% of total Zeta ${ml}</span></div>
      <div class="chart-wrap" style="height:260px"><canvas id="ch-zm-atc4"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">ATC4 Market Penetration
        <span class="chart-box-sub">Zeta share within each therapeutic class</span></div>
      <div class="tbl-scroll" style="max-height:250px"><table id="tbl-zm-atc4"><thead><tr>
        <th>#</th><th>ATC4</th><th>Zeta ${ml}</th><th>Portfolio %</th><th>Growth</th><th>Mkt ${ml}</th><th>Penetration</th>
      </tr></thead><tbody>
      ${atc4List.slice(0,12).map((x,i)=>`<tr>
        <td><span class="rank-badge ${i<3?'top3':''}">${i+1}</span></td>
        <td style="font-size:11px" title="${LOOKUPS.atc4s[x.a]||''}">${(LOOKUPS.atc4s[x.a]||'').substring(0,22)}</td>
        <td>${fmtLCV(x.lcv)}</td>
        <td>${fmtPct(x.lcv/atc4Total)}</td>
        <td>${fmtGrowth(x.gr)}</td>
        <td>${fmtLCV(x.mktLcv)}</td>
        <td style="${x.share>=0.3?'color:#2fc97e':x.share>=0.15?'color:#ffb800':'color:#e05c5c'};font-weight:600">${fmtPct(x.share)}</td>
      </tr>`).join('')}
      </tbody></table></div>
    </div>
  </div>`;

  document.getElementById(SEC).innerHTML = aiInsightStrip(SEC) + pageHtml;

  // ── Strategic bubble chart — direct Chart.js for precise axis control ─────────
  const _tc=v=>getComputedStyle(document.documentElement).getPropertyValue(v);

  // Y-axis: use 90th-percentile cap to prevent outliers stretching the scale
  const allSharePcts  = bubbleDm1.map(x=>x.zetaShare*100).sort((a,b)=>a-b);
  const p90Share      = allSharePcts.length ? allSharePcts[Math.floor(allSharePcts.length*0.90)] : 20;
  const yMax          = Math.min(100, Math.ceil((p90Share+8)/5)*5);
  const yStep         = yMax<=15?2:yMax<=40?5:10;

  // X-axis: 5th–95th percentile range + padding to avoid single-outlier stretch
  const allGrPcts     = bubbleDm1.map(x=>x.mktGr*100).sort((a,b)=>a-b);
  const p05Gr = allGrPcts.length ? allGrPcts[Math.floor(allGrPcts.length*0.05)] : -10;
  const p95Gr = allGrPcts.length ? allGrPcts[Math.floor(allGrPcts.length*0.95)] :  20;
  const xPad  = Math.max(3, (p95Gr-p05Gr)*0.12);
  const xMin  = Math.floor((p05Gr-xPad)/5)*5;
  const xMax2 = Math.ceil( (p95Gr+xPad)/5)*5;

  // Quadrant reference lines (median growth, avg share)
  const medMktGrPct   = allGrPcts.length ? allGrPcts[Math.floor(allGrPcts.length/2)] : 0;
  const avgSharePct2  = avgShare*100;

  destroyChart('ch-zm-bubble');
  const _bCtx = document.getElementById('ch-zm-bubble')?.getContext('2d');
  if(_bCtx) {
    charts['ch-zm-bubble'] = new Chart(_bCtx, {
      type:'bubble',
      data:{ datasets: bubbleDS },
      options:{
        responsive:true, maintainAspectRatio:false,
        plugins:{
          legend:{labels:{color:_tc('--txt2'),font:{size:10}}},
          tooltip:{callbacks:{label:ctx=>{
            const d=ctx.raw;
            return [d.name,`Top Product: ${d.topProd}`,`Mkt Growth: ${d.x}%`,`Zeta Share: ${d.y}%`,
                    `Mkt Size: ${fmtLCV(d.mktLcv)}`,
                    `RGI: ${d.rgi!=null?d.rgi.toFixed(2):'—'}`,
                    `Share Δ: ${d.sdelta>=0?'+':''}${(d.sdelta*100).toFixed(2)}pp`];
          }}}
        },
        scales:{
          x:{min:xMin, max:xMax2,
             title:{display:true,text:'Market Growth (%)',color:_tc('--txt2'),font:{size:11}},
             ticks:{color:_tc('--txt3'),callback:v=>v.toFixed(0)+'%'},
             grid:{color:'rgba(255,255,255,.04)'}},
          y:{min:0, max:yMax,
             title:{display:true,text:'Zeta Market Share (%)',color:_tc('--txt2'),font:{size:11}},
             ticks:{color:_tc('--txt3'),stepSize:yStep,callback:v=>v+'%'},
             grid:{color:'rgba(255,255,255,.04)'}}
        }
      },
      plugins:[{
        id:'zmQuadrant',
        afterDraw(chart){
          const {ctx:c,chartArea:{left,right,top,bottom},scales:{x,y}}=chart;
          const xM=x.getPixelForValue(medMktGrPct);
          const yM=y.getPixelForValue(avgSharePct2);
          // Quadrant lines
          c.save();
          c.strokeStyle='rgba(255,255,255,0.14)'; c.lineWidth=1; c.setLineDash([5,4]);
          c.beginPath(); c.moveTo(xM,top);  c.lineTo(xM,bottom); c.stroke();
          c.beginPath(); c.moveTo(left,yM); c.lineTo(right,yM);  c.stroke();
          c.restore();
          // Quadrant labels
          c.save();
          c.font='bold 9px -apple-system,sans-serif';
          c.fillStyle='rgba(255,255,255,0.20)';
          c.fillText('★ STAR',         xM+8,   top+14);
          c.fillText('■ HARVEST',       left+8, top+14);
          c.fillText('◎ OPPORTUNITY',   xM+8,   bottom-6);
          c.fillText('⚠ REVIEW',        left+8, bottom-6);
          c.restore();
          // Market name labels — top 8 bubbles by r only, basic collision guard
          c.save();
          c.font='9px -apple-system,sans-serif';
          c.textAlign='center';
          const allBubs=[];
          chart.data.datasets.forEach(ds=>ds.data.forEach(d=>allBubs.push({...d,
            xp:x.getPixelForValue(d.x), yp:y.getPixelForValue(d.y)})));
          allBubs.sort((a,b)=>b.r-a.r); // largest first
          const placed=[];
          allBubs.slice(0,8).forEach(d=>{
            const lx=d.xp, ly=d.yp-d.r-4;
            // skip if overlaps a placed label (20px guard)
            const clash=placed.some(p=>Math.abs(p.x-lx)<60&&Math.abs(p.y-ly)<14);
            if(!clash){
              c.fillStyle='rgba(255,255,255,0.85)';
              c.fillText(d.name, lx, ly);
              placed.push({x:lx,y:ly});
            }
          });
          c.restore();
        }
      }]
    });
  }

  // ── Share Win/Loss bar ───────────────────────────────────────────────────────
  hBarChart('ch-zm-wl',
    wlItems.map(x=>(LOOKUPS.dm1s[x.d]||'').substring(0,22)),
    wlItems.map(x=>+(x.shareDelta*100).toFixed(3)),
    wlItems.map(x=>x.shareDelta>=0?'rgba(47,201,126,.8)':'rgba(224,92,92,.8)'),
    {plugins:{tooltip:{callbacks:{label:ctx=>`Share Δ: ${ctx.parsed.x>=0?'+':''}${ctx.parsed.x.toFixed(2)}pp`}}},
     scales:{x:{ticks:{color:_tc('--txt3'),callback:v=>v+'pp'},grid:{color:'rgba(255,255,255,.04)'}},
             y:{ticks:{color:_tc('--txt3')}}}}
  );

  // ── ATC4 donut ───────────────────────────────────────────────────────────────
  donutChart('ch-zm-atc4',
    atc4List.slice(0,7).map(x=>(LOOKUPS.atc4s[x.a]||'').substring(0,20)),
    atc4List.slice(0,7).map(x=>x.lcv),{
      plugins:{
        legend:{position:'bottom',labels:{boxWidth:10,font:{size:9},color:_tc('--txt2')}},
        tooltip:{callbacks:{label:ctx=>`${ctx.label}: ${fmtPct(ctx.parsed/atc4Total)} (${fmtLCV(ctx.parsed)})`}}
      }
    });

  makeSortable('tbl-zm2');
  makeSortable('tbl-zm-atc4');
}

// ===================== ZETA COMPETITOR INTELLIGENCE =====================


function renderZetaComp() {
  const ml  = STATE.metric.toUpperCase();
  const N   = flat.length;
  const rangeLabel = {mat:'MAT',ytd:'YTD',curr:'Month',all:'All','3m':'3M','6m':'6M'}[STATE.timeRange]||STATE.timeRange;

  // ── Period indices ──────────────────────────────────────────────────────
  const curPidxs  = getPeriodIndices(STATE.timeRange);
  const prevPidxs = getPrevPeriodIndices(STATE.timeRange);
  const momPidx   = new Set([NP-1]);
  const prevMomPidx = new Set([NP-2]);

  // ── DM1 filter — driven by global topbar DM1 selector ─────────────────
  const activeDm1 = STATE.fDm1Sel.size > 0 ? STATE.fDm1Sel : null;
  const _zcFilterFn = dimFilter(); // full filter: Corp/ATC4/DM2/Line/BU

  // ── BU-driven DM1 scope (SFE/CEO/VP/BEX selecting a BU) ────────────────
  // Derive the set of DM1 markets where Zeta competes for the selected BU(s).
  // Only applied when no explicit DM1 is selected (DM1 takes priority).
  // Use the same ZETA_IDX constant used everywhere else in this function
  let _zcBuDm1Set = null;
  let _zcActiveBuLabel = null;
  if(activeDm1 === null && STATE.fBuSel && STATE.fBuSel.size > 0){
    _zcBuDm1Set = new Set();
    for(let j=0;j<N;j+=10){
      if(flat[j+CI] !== ZETA_IDX) continue;          // Zeta rows only
      if(!STATE.fBuSel.has(flat[j+BUCI])) continue;  // matching BU
      _zcBuDm1Set.add(flat[j+D1I]);                  // collect their DM1 markets
    }
    _zcActiveBuLabel = [...STATE.fBuSel].map(i=>LOOKUPS.bus[i]||'').filter(Boolean).join(', ');
    if(_zcBuDm1Set.size === 0) _zcBuDm1Set = null; // fallback: no matching DM1s
  }

  // ── Single-pass scan ────────────────────────────────────────────────────
  const corpCur  = new Map();  // c → {lcv,su}
  const corpPrev = new Map();  // c → {lcv,su}
  const prodByCorp = new Map();     // c → Map(p → {lcv,su})
  const prodByCorpPrev = new Map(); // c → Map(p → {lcv,su})
  const corpFirstP = new Map(); // c → earliest period index (new entrant detection)
  const monthlyCorps = new Map(); // t → Map(c→{lcv,su}) for trend
  let mktLcvCur=0, mktSuCur=0, mktLcvPrev=0, mktSuPrev=0;

  for(let i=0;i<N;i+=10){
    const c=flat[i], t=flat[i+2], lcv=flat[i+6], su=flat[i+7];
    // DM1 filter: activeDm1 is now a Set (fDm1Sel)
    if(activeDm1!==null && !activeDm1.has(flat[i+4])) continue;
    // BU-driven DM1 scope (only when no explicit DM1 selected)
    if(activeDm1===null && _zcBuDm1Set!==null && !_zcBuDm1Set.has(flat[i+D1I])) continue;
    // Full dimFilter: Corp/ATC4/DM2/Line/BU
    if(_zcFilterFn){var _d2=flat[i+D2I],_ln=flat[i+LINEI],_bu=flat[i+BUCI];
      if(!_zcFilterFn(c,flat[i+1],flat[i+2],flat[i+3],flat[i+D1I],_d2,_ln,_bu)) continue;}
    // Track first-ever period (new entrant check)
    const fp=corpFirstP.get(c); if(fp===undefined||t<fp) corpFirstP.set(c,t);
    // Monthly for trend / rank trajectory (last 24M)
    if(t>=NP-24){
      if(!monthlyCorps.has(t)) monthlyCorps.set(t,new Map());
      const mc=monthlyCorps.get(t);
      const mv=mc.get(c)||{lcv:0,su:0}; mv.lcv+=lcv; mv.su+=su; mc.set(c,mv);
    }
    if(curPidxs.has(t)){
      mktLcvCur+=lcv; mktSuCur+=su;
      const v=corpCur.get(c)||{lcv:0,su:0}; v.lcv+=lcv; v.su+=su; corpCur.set(c,v);
      const p=flat[i+1];
      if(!prodByCorp.has(c)) prodByCorp.set(c,new Map());
      const pm=prodByCorp.get(c); const pv2=pm.get(p)||{lcv:0,su:0}; pv2.lcv+=lcv; pv2.su+=su; pm.set(p,pv2);
    }
    if(prevPidxs.has(t)){
      mktLcvPrev+=lcv; mktSuPrev+=su;
      const v=corpPrev.get(c)||{lcv:0,su:0}; v.lcv+=lcv; v.su+=su; corpPrev.set(c,v);
      const p=flat[i+1];
      if(!prodByCorpPrev.has(c)) prodByCorpPrev.set(c,new Map());
      const pm2=prodByCorpPrev.get(c); const pp2=pm2.get(p)||{lcv:0,su:0}; pp2.lcv+=lcv; pp2.su+=su; pm2.set(p,pp2);
    }
  }

  // ── Derived values ──────────────────────────────────────────────────────
  const mktCurVal  = STATE.metric==='lcv' ? mktLcvCur  : mktSuCur;
  const mktPrevVal = STATE.metric==='lcv' ? mktLcvPrev : mktSuPrev;
  const mktGr      = growth(mktCurVal, mktPrevVal);

  // Build ranked corp list
  const allCorps = [...corpCur.entries()].map(([c,v])=>{
    const pv  = corpPrev.get(c)||{lcv:0,su:0};
    const cur = MV(v), prev = MV(pv);
    const gr  = prev>0 ? growth(cur,prev) : (cur>0?9.99:0);
    const EVI = mktGr>-1 ? Math.round(((1+gr)/(1+(mktGr||0)))*100) : 100;
    const shareCur  = mktCurVal>0  ? cur/mktCurVal  : 0;
    const sharePrev = mktPrevVal>0 ? prev/mktPrevVal : 0;
    const shareChgPp = (shareCur-sharePrev)*100;
    const fp = corpFirstP.get(c)??NP;
    const isNew    = fp >= NP-12;                         // entered within last 12M
    const isLaunch = prev>0 && prev<cur*0.12 && cur>0;   // prev was <12% of current
    return {c, cur, prev, gr, EVI, shareCur, sharePrev, shareChgPp,
            isNew, isLaunch, lcv:v.lcv, su:v.su, lcvPrev:pv.lcv, suPrev:pv.su};
  }).filter(x=>x.cur>0).sort((a,b)=>b.cur-a.cur);

  // Assign current ranks
  allCorps.forEach((x,i)=>x.rankCur=i+1);

  // Assign previous ranks
  const prevRanked=[...corpPrev.entries()].map(([c,v])=>({c,val:MV(v)})).sort((a,b)=>b.val-a.val);
  prevRanked.forEach((x,i)=>{
    const e=allCorps.find(cc=>cc.c===x.c); if(e) e.rankPrev=i+1;
  });
  allCorps.forEach(x=>{ x.rankDelta=(x.rankPrev||x.rankCur)-x.rankCur; });

  // Zeta position
  const zetaEntry = allCorps.find(x=>x.c===ZETA_IDX)||{c:ZETA_IDX,cur:0,prev:0,gr:0,EVI:100,shareCur:0,sharePrev:0,shareChgPp:0,rankCur:allCorps.length+1,rankPrev:allCorps.length+1,rankDelta:0,isNew:false,isLaunch:false};
  const zetaRank  = zetaEntry.rankCur;
  const zetaGr    = zetaEntry.gr;
  const zetaEVI   = zetaEntry.EVI;

  // Battlefield zones
  const aboveZeta = allCorps.filter(x=>x.rankCur<zetaRank).slice(-3).reverse(); // up to 3 just above
  const belowZeta = allCorps.filter(x=>x.rankCur>zetaRank).slice(0,3);          // up to 3 just below

  // Market KPIs
  const top3Share  = allCorps.slice(0,3).reduce((s,x)=>s+x.shareCur,0);
  const top5Share  = allCorps.slice(0,5).reduce((s,x)=>s+x.shareCur,0);
  const hhi        = allCorps.reduce((s,x)=>s+(x.shareCur*100)**2,0);
  const fragLabel  = hhi>2500?'Concentrated':hhi>1500?'Moderate':'Fragmented';
  const leader     = allCorps[0]||{cur:0,c:0};
  const gapToLeader= zetaEntry.cur>0 && leader.c!==ZETA_IDX ? leader.cur-zetaEntry.cur : 0;

  // Threat / opportunity counts
  const risingThreats = belowZeta.filter(x=>x.gr>zetaGr&&x.EVI>=110).length;
  const aboveThreats  = aboveZeta.filter(x=>x.EVI>=110).length;
  const newEntrants   = allCorps.filter(x=>x.isNew).length;

  // Outgrowers
  const outgrowMkt  = allCorps.filter(x=>x.c!==ZETA_IDX&&x.EVI>=110&&!x.isLaunch);
  const outgrowZeta = allCorps.filter(x=>x.c!==ZETA_IDX&&x.gr>zetaGr&&!x.isLaunch&&x.cur>zetaEntry.cur*0.05);

  // Share flow: who gained / lost
  const shareGainers = allCorps.filter(x=>x.c!==ZETA_IDX&&x.shareChgPp>0).sort((a,b)=>b.shareChgPp-a.shareChgPp);
  const shareLosers  = allCorps.filter(x=>x.c!==ZETA_IDX&&x.shareChgPp<0).sort((a,b)=>a.shareChgPp-b.shareChgPp);

  // If Zeta gained share — who did it come from?
  const zetaShareMove = zetaEntry.shareChgPp;
  let shareFlowNarrative='';
  if(Math.abs(zetaShareMove)>0.05){
    if(zetaShareMove>0){
      const sources=shareLosers.slice(0,3).map(x=>`${(LOOKUPS.corps[x.c]||'').substring(0,15)} (${x.shareChgPp.toFixed(2)}pp)`).join(', ');
      shareFlowNarrative=`Zeta gained <strong>+${zetaShareMove.toFixed(2)}pp</strong> share — primary donors: ${sources||'distributed across multiple players'}.`;
    } else {
      const receivers=shareGainers.slice(0,3).map(x=>`${(LOOKUPS.corps[x.c]||'').substring(0,15)} (+${x.shareChgPp.toFixed(2)}pp)`).join(', ');
      shareFlowNarrative=`Zeta lost <strong>${zetaShareMove.toFixed(2)}pp</strong> share — primary recipients: ${receivers||'distributed across market'}.`;
    }
  }

  // ── Rank change narrative: where did rank go? ──────────────────────────
  function rankNarrative(x){
    if(!x.rankPrev) return '';
    if(x.rankDelta>0) return `▲${x.rankDelta} (was #${x.rankPrev})`;
    if(x.rankDelta<0) return `▼${Math.abs(x.rankDelta)} (was #${x.rankPrev})`;
    return 'No change';
  }

  // When Zeta rank changed — who did it pass / get passed by?
  let zetaRankNarr='';
  if(zetaEntry.rankDelta>0){
    const passed=allCorps.filter(x=>x.rankCur>zetaRank&&x.rankCur<=zetaRank+zetaEntry.rankDelta).map(x=>(LOOKUPS.corps[x.c]||'').substring(0,16));
    zetaRankNarr=`Zeta climbed ▲${zetaEntry.rankDelta} places — passed: ${passed.join(', ')||'competitors'}.`;
  } else if(zetaEntry.rankDelta<0){
    const passedBy=allCorps.filter(x=>x.rankCur<zetaRank&&x.rankCur>=zetaRank+zetaEntry.rankDelta).map(x=>(LOOKUPS.corps[x.c]||'').substring(0,16));
    zetaRankNarr=`Zeta dropped ▼${Math.abs(zetaEntry.rankDelta)} places — overtaken by: ${passedBy.join(', ')||'competitors'}.`;
  }

  // Trend data for charts
  const trendP = Array.from({length:Math.min(24,NP)},(_,i)=>NP-Math.min(24,NP)+i);
  const topCompsForTrend = [zetaEntry, ...allCorps.filter(x=>x.c!==ZETA_IDX).slice(0,3)];
  const TREND_COLORS = ['#9775fa','#4c6ef5','#36c994','#ff9f45'];

  // ── Battlefield card helper ─────────────────────────────────────────────
  // ── Product pills helper ───────────────────────────────────────────────
  function prodPills(c, maxShow=3, showVal=false){
    const pm = prodByCorp.get(c);
    if(!pm || pm.size===0) return '<span style="color:var(--txt3);font-size:10px">—</span>';
    const sorted = [...pm.entries()]
      .map(([p,v])=>({p, val:STATE.metric==='lcv'?v.lcv:v.su}))
      .sort((a,b)=>b.val-a.val);
    const shown = sorted.slice(0, maxShow);
    const extra = sorted.length - maxShow;
    const corpTotal = shown.reduce((s,x)=>s+x.val,0) + sorted.slice(maxShow).reduce((s,x)=>s+x.val,0);
    const pills = shown.map(({p,val})=>{
      const pct = corpTotal>0 ? ' '+Math.round(val/corpTotal*100)+'%' : '';
      return `<span style="background:var(--bg3);border:1px solid var(--border);border-radius:8px;padding:1px 7px;font-size:10px;color:var(--txt2);white-space:nowrap;line-height:1.8" title="${LOOKUPS.prods[p]||''}">${(LOOKUPS.prods[p]||'').substring(0,20)}${showVal?pct:''}</span>`;
    }).join('');
    const more = extra>0 ? `<span style="font-size:10px;color:var(--txt3);white-space:nowrap">+${extra} more</span>` : '';
    return `<div style="display:flex;gap:3px;flex-wrap:wrap;align-items:center">${pills}${more}</div>`;
  }

  function bfCard(x, zone){
    if(!x) return `<div style="background:var(--bg3);border:1px dashed var(--border);border-radius:12px;padding:16px;display:flex;align-items:center;justify-content:center;color:var(--txt3);font-size:12px">No player</div>`;
    const name=(LOOKUPS.corps[x.c]||'').substring(0,18);
    const grStr=x.gr>=9?'New':((x.gr*100).toFixed(1)+'%');
    const grCol=x.gr>mktGr?'#36c994':x.gr>=0?'#9da8c5':'#ff5c6b';
    const eviCol=x.EVI>=110?'#36c994':x.EVI>=95?'#9da8c5':'#ff5c6b';
    const gapSign=zone==='above'?'gap ↑':'gap ↓';
    const gapVal=Math.abs(x.cur-zetaEntry.cur);
    const rankChg=x.rankDelta>0?`<span style="color:#36c994;font-size:11px">▲${x.rankDelta}</span>`:x.rankDelta<0?`<span style="color:#ff5c6b;font-size:11px">▼${Math.abs(x.rankDelta)}</span>`:`<span style="color:var(--txt3);font-size:11px">—</span>`;
    const launchFlag=x.isLaunch?'<span style="background:rgba(255,200,0,.2);color:#ffcc00;font-size:10px;padding:2px 6px;border-radius:10px;margin-left:4px">🚀Launch</span>':'';
    const newFlag=x.isNew?'<span style="background:rgba(255,92,107,.2);color:#ff5c6b;font-size:10px;padding:2px 6px;border-radius:10px;margin-left:4px">🆕New</span>':'';
    const borderCol=zone==='zeta'?'var(--acc5)':zone==='above'?(x.EVI>=110?'rgba(255,92,107,.5)':'rgba(255,159,69,.4)'):(x.EVI>=110?'rgba(255,159,69,.6)':'rgba(54,201,148,.3)');
    return `<div style="background:var(--bg2);border:1px solid ${borderCol};border-radius:12px;padding:14px;display:flex;flex-direction:column;gap:6px;${zone==='zeta'?'box-shadow:0 0 18px rgba(151,117,250,.2)':''}">
      <div style="display:flex;align-items:center;justify-content:space-between">
        <span style="background:var(--bg3);border-radius:6px;padding:2px 8px;font-size:12px;font-weight:700;color:var(--txt2)">#${x.rankCur}</span>
        <span style="font-size:11px">${rankChg}</span>
      </div>
      <div style="font-size:13px;font-weight:700;color:var(--txt1);line-height:1.3">${name}${launchFlag}${newFlag}</div>
      <div style="font-size:clamp(16px,1.3vw,20px);font-weight:700;color:${zone==='zeta'?'#9775fa':'var(--txt1)'}">${fmtLCV(x.cur)}</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
        <span style="color:${grCol};font-size:12px;font-weight:600">${grStr} ${x.gr>mktGr?'▲ mkt':x.gr>=0?'≈ mkt':'▼ mkt'}</span>
        <span style="color:${eviCol};font-size:11px">EVI ${x.EVI}</span>
      </div>
      <div style="font-size:11px;color:var(--txt3)">${gapSign}: ${fmtLCV(gapVal)}</div>
      <div style="font-size:11px;color:var(--txt2)">Share: ${fmtPct(x.shareCur)} <span style="color:${x.shareChgPp>=0?'#36c994':'#ff5c6b'}">${x.shareChgPp>=0?'+':''}${x.shareChgPp.toFixed(2)}pp</span></div>
      <div style="margin-top:4px;border-top:1px solid var(--border);padding-top:5px">${prodPills(x.c,2,true)}</div>
    </div>`;
  }

  const eviCol   = zetaEVI>=110?'#36c994':zetaEVI>=95?'#9da8c5':'#ff5c6b';
  const hl       = STATE.metric==='lcv'?'style="background:rgba(76,110,245,.10)"':'style="background:rgba(32,178,170,.10)"';
  const hl2      = STATE.metric==='lcv'?'background:rgba(76,110,245,.07)':'background:rgba(32,178,170,.07)';

  // ── HTML ───────────────────────────────────────────────────────────────
  const h = `
  <div class="section-title">⚔️ Zeta Competitor Intelligence${activeDm1!==null?` — <span style="color:var(--acc2);font-size:clamp(13px,1vw,16px)">${(LOOKUPS.dm1s[activeDm1]||"")}</span>`:_zcActiveBuLabel?` — <span style="color:var(--acc2);font-size:clamp(13px,1vw,16px)">BU: ${_zcActiveBuLabel}</span>`:""}</div>
  <div class="section-sub" style="display:flex;align-items:center;gap:10px;flex-wrap:wrap">
    Full market competitive analysis — ${rangeLabel} | ${refPeriodLabel()} | Metric: ${ml}
    ${activeDm1!==null
      ?`<span style="display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:20px;background:rgba(54,201,148,.15);border:1px solid var(--acc2);color:var(--acc2);font-size:12px;font-weight:600">📍 ${(LOOKUPS.dm1s[activeDm1]||'').substring(0,32)}</span>`
      :_zcActiveBuLabel
        ?`<span style="display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:20px;background:rgba(151,117,250,.15);border:1px solid var(--acc5);color:var(--acc5);font-size:12px;font-weight:600">🏢 BU: ${_zcActiveBuLabel} — ${_zcBuDm1Set?_zcBuDm1Set.size:0} markets</span>`
        :'<span style="font-size:12px;color:var(--txt3)">Select DM1 or BU in topbar to filter</span>'}
  </div>

  <!-- Layer 1: Market Landscape -->
  <div class="zeta-layer-lbl">🌍 Market Landscape</div>
  <div class="kpi-grid">
    <div class="kpi-card blue">
      <div class="kpi-label">Total Market ${ml}</div>
      <div class="kpi-value">${fmtLCV(mktCurVal)}</div>
      <div class="kpi-sub">${STATE.metric==='lcv'?'EGP':'Standard Units'}</div>
      <div>${fmtGrowth(mktGr)}</div>
    </div>
    <div class="kpi-card green">
      <div class="kpi-label">Active Corporations</div>
      <div class="kpi-value">${allCorps.length}</div>
      <div class="kpi-sub">${newEntrants>0?`🆕 ${newEntrants} new entrant${newEntrants>1?'s':''}`:'No new entrants'}</div>
    </div>
    <div class="kpi-card orange">
      <div class="kpi-label">Top 3 Concentration</div>
      <div class="kpi-value">${fmtPct(top3Share)}</div>
      <div class="kpi-sub">Top 5: ${fmtPct(top5Share)}</div>
    </div>
    <div class="kpi-card ${hhi>2500?'red':hhi>1500?'orange':'blue'}">
      <div class="kpi-label">Market Structure</div>
      <div class="kpi-value" style="font-size:clamp(16px,1.3vw,22px)">${fragLabel}</div>
      <div class="kpi-sub">HHI: ${Math.round(hhi)}</div>
    </div>
    <div class="kpi-card purple">
      <div class="kpi-label">Outgrowing Market</div>
      <div class="kpi-value">${outgrowMkt.length}</div>
      <div class="kpi-sub">EVI ≥ 110 (excl. launches)</div>
    </div>
    <div class="kpi-card red">
      <div class="kpi-label">Outgrowing Zeta</div>
      <div class="kpi-value">${outgrowZeta.length}</div>
      <div class="kpi-sub">Competitors faster than Zeta</div>
    </div>
  </div>

  <!-- Layer 2: Zeta Competitive Position -->
  <div class="zeta-layer-lbl">📍 Zeta Competitive Position</div>
  <div class="kpi-grid">
    <div class="kpi-card purple">
      <div class="kpi-label">Market Rank</div>
      <div class="kpi-value">#${zetaRank}</div>
      <div class="kpi-sub">
        <span class="badge ${zetaEntry.rankDelta>0?'badge-up':zetaEntry.rankDelta<0?'badge-down':'badge-neutral'}">
          ${zetaEntry.rankDelta>0?'▲'+zetaEntry.rankDelta:zetaEntry.rankDelta<0?'▼'+Math.abs(zetaEntry.rankDelta):'Stable'}
        </span> vs prior ${rangeLabel}
      </div>
    </div>
    <div class="kpi-card" style="border-color:${eviCol}">
      <div class="kpi-label">Evolution Index</div>
      <div class="kpi-value" style="color:${eviCol}">${zetaEVI}</div>
      <div class="kpi-sub">${zetaEVI>=110?'🚀 Outperforming':zetaEVI>=95?'📊 In-Line':'📉 Underperforming'} market</div>
    </div>
    <div class="kpi-card green">
      <div class="kpi-label">Market Share (${ml})</div>
      <div class="kpi-value">${fmtPct(zetaEntry.shareCur)}</div>
      <div class="kpi-sub">
        <span class="badge ${zetaEntry.shareChgPp>=0?'badge-up':'badge-down'}">${zetaEntry.shareChgPp>=0?'+':''}${zetaEntry.shareChgPp.toFixed(2)}pp</span>
      </div>
    </div>
    <div class="kpi-card blue">
      <div class="kpi-label">Gap to Leader</div>
      <div class="kpi-value" style="font-size:clamp(14px,1.2vw,20px)">${zetaRank===1?'🏆 Leader':'-'+fmtLCV(gapToLeader)}</div>
      <div class="kpi-sub">${leader.c!==ZETA_IDX?(LOOKUPS.corps[leader.c]||'').substring(0,18):'Market leader'}</div>
    </div>
    <div class="kpi-card orange">
      <div class="kpi-label">Rising Threats Below</div>
      <div class="kpi-value">${risingThreats}</div>
      <div class="kpi-sub">EVI ≥ 110, ranked below Zeta</div>
    </div>
    <div class="kpi-card red">
      <div class="kpi-label">Threats Above (EVI≥110)</div>
      <div class="kpi-value">${aboveThreats}</div>
      <div class="kpi-sub">Competitors above + outgrowing mkt</div>
    </div>
  </div>

  <!-- Battlefield View -->
  <div class="zeta-layer-lbl">🎯 Battlefield — Ranks Around Zeta (#${zetaRank})</div>
  <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:8px;margin-bottom:16px;overflow-x:auto">
    ${aboveZeta.length<3?`<div style="background:var(--bg3);border:1px dashed var(--border);border-radius:12px;padding:12px;display:flex;align-items:center;justify-content:center;color:var(--txt3);font-size:11px">—</div>`.repeat(3-aboveZeta.length):''}
    ${[...aboveZeta].reverse().map(x=>bfCard(x,'above')).join('')}
    ${bfCard(zetaEntry,'zeta')}
    ${belowZeta.map(x=>bfCard(x,'below')).join('')}
    ${belowZeta.length<3?`<div style="background:var(--bg3);border:1px dashed var(--border);border-radius:12px;padding:12px;display:flex;align-items:center;justify-content:center;color:var(--txt3);font-size:11px">—</div>`.repeat(3-belowZeta.length):''}
  </div>

  <!-- Charts Row 1: Competitive bar + Growth rate -->
  <div class="chart-row cols2">
    <div class="chart-box">
      <div class="chart-box-title">Market Share — Top 15 Players ${ml}
        <span class="chart-box-sub">Zeta highlighted</span></div>
      <div class="chart-wrap" style="height:280px"><canvas id="ch-zci-bar"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">Growth Rate Comparison — ${rangeLabel}
        <span class="chart-box-sub">vs market avg ${((mktGr||0)*100).toFixed(1)}% | ⚠️ launch-boosted flagged</span></div>
      <div class="chart-wrap" style="height:280px"><canvas id="ch-zci-gr"></canvas></div>
    </div>
  </div>

  <!-- Charts Row 2: Trend + Share delta -->
  <div class="chart-row cols2">
    <div class="chart-box">
      <div class="chart-box-title">24M Revenue Trend — Top 4 + Zeta
        <span class="chart-box-sub">${ml} monthly</span></div>
      <div class="chart-wrap" style="height:260px"><canvas id="ch-zci-trend"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">Share Gain / Loss — ${rangeLabel}
        <span class="chart-box-sub">pp change vs prior period — top 12 movers</span></div>
      <div class="chart-wrap" style="height:260px"><canvas id="ch-zci-share"></canvas></div>
    </div>
  </div>

  <!-- New Entrants Panel (conditional) -->
  ${newEntrants>0?`
  <div class="zeta-layer-lbl">🆕 New Entrants</div>
  <div class="kpi-grid">
    ${allCorps.filter(x=>x.isNew).slice(0,6).map(x=>`
    <div class="kpi-card red">
      <div class="kpi-label">New Player</div>
      <div class="kpi-value" style="font-size:clamp(12px,1vw,16px)">${(LOOKUPS.corps[x.c]||'').substring(0,20)}</div>
      <div class="kpi-sub">${fmtLCV(x.cur)} | Rank #${x.rankCur}</div>
      <div style="margin-top:4px">${prodPills(x.c,3,false)}</div>
      <div style="margin-top:4px"><span class="badge badge-down">New entrant</span></div>
    </div>`).join('')}
  </div>`:''}

  <!-- Full Competitive League Table -->
  <div class="tbl-wrap">
    <div class="tbl-head">
      <span class="tbl-head-title">📊 Full Competitive League Table — ${rangeLabel} | ${ml}</span>
      <input class="tbl-search" placeholder="Search corporation..." oninput="filterTbl(this,'tbl-zci-body')">
    </div>
    <div class="tbl-scroll"><table id="tbl-zci">
      <thead><tr>
        <th>Rank</th><th>Corporation</th>
        <th ${hl}>${ml}</th><th>Share %</th><th>Share Δ pp</th>
        <th>Growth</th><th>EVI</th><th>Rank Δ</th><th>Flags</th><th>Products</th>
      </tr></thead>
      <tbody id="tbl-zci-body">
      ${allCorps.map((x,i)=>{
        const isZeta=x.c===ZETA_IDX;
        const bg=isZeta?`style="${hl2};outline:1px solid var(--acc5)"`:x.isNew?'style="background:rgba(255,92,107,.05)"':'';
        const rdStr=x.rankDelta>0?`<span class="badge badge-up">▲${x.rankDelta}</span>`:x.rankDelta<0?`<span class="badge badge-down">▼${Math.abs(x.rankDelta)}</span>`:'<span class="badge badge-neutral">—</span>';
        const flags=[isZeta?'⭐ Zeta':'',x.isNew?'🆕 New':'',x.isLaunch?'🚀 Launch':'',x.EVI>=120&&!x.isLaunch?'🔥 Star':''].filter(Boolean).join(' ');
        const prevRankNarr=x.rankDelta!==0&&x.rankPrev?` was #${x.rankPrev}`:'';
        return `<tr ${bg}>
          <td><span class="rank-badge ${i<3?'top3':''}">${i+1}</span>${prevRankNarr?`<span style="font-size:10px;color:var(--txt3)"> ${prevRankNarr}</span>`:''}</td>
          <td style="font-weight:${isZeta?700:400}">${LOOKUPS.corps[x.c]||''}</td>
          <td ${isZeta?hl:''}>${fmtLCV(x.cur)}</td>
          <td>${fmtPct(x.shareCur)}</td>
          <td><span class="badge ${x.shareChgPp>=0?'badge-up':'badge-down'}">${x.shareChgPp>=0?'+':''}${x.shareChgPp.toFixed(2)}pp</span></td>
          <td>${x.prev>0?fmtGrowth(x.gr):'<span class="badge badge-neutral">New</span>'}</td>
          <td style="text-align:center;font-weight:700;color:${x.EVI>=110?'#36c994':x.EVI>=95?'var(--txt2)':'#ff5c6b'}">${x.prev>0?x.EVI:'—'}</td>
          <td style="text-align:center">${rdStr}</td>
          <td style="font-size:11px">${flags}</td>
          <td style="min-width:160px">${prodPills(x.c,3,true)}</td>
        </tr>`;
      }).join('')}
      </tbody>
    </table></div>
  </div>

  <!-- Share Flow Table -->
  <div class="chart-row cols2">
    <div class="tbl-wrap" style="margin:0">
      <div class="tbl-head"><span class="tbl-head-title">📈 Share Gainers (${rangeLabel})</span></div>
      <div class="tbl-scroll" style="max-height:240px"><table>
        <thead><tr><th>#</th><th>Corporation</th><th>Top Products</th><th>Share Gain (pp)</th><th>Growth</th></tr></thead>
        <tbody>
        ${[zetaEntry,...shareGainers].filter(x=>x.shareChgPp>0).sort((a,b)=>b.shareChgPp-a.shareChgPp).slice(0,8).map((x,i)=>{
          const isZeta=x.c===ZETA_IDX;
          const trAttr=isZeta?'style="'+hl2+'"':'';
          return `<tr ${trAttr}><td>${i+1}</td>
          <td style="font-weight:${isZeta?700:400}">${(LOOKUPS.corps[x.c]||'').substring(0,22)}${isZeta?' ⭐':''}</td>
          <td>${prodPills(x.c,2,false)}</td>
          <td><span class="badge badge-up">+${x.shareChgPp.toFixed(2)}pp</span></td>
          <td>${fmtGrowth(x.gr)}</td></tr>`;
        }).join('')}
        </tbody>
      </table></div>
    </div>
    <div class="tbl-wrap" style="margin:0">
      <div class="tbl-head"><span class="tbl-head-title">📉 Share Losers (${rangeLabel})</span></div>
      <div class="tbl-scroll" style="max-height:240px"><table>
        <thead><tr><th>#</th><th>Corporation</th><th>Top Products</th><th>Share Loss (pp)</th><th>Growth</th></tr></thead>
        <tbody>
        ${[zetaEntry,...shareLosers].filter(x=>x.shareChgPp<0).sort((a,b)=>a.shareChgPp-b.shareChgPp).slice(0,8).map((x,i)=>{
          const isZeta=x.c===ZETA_IDX;
          const trAttr=isZeta?'style="'+hl2+'"':'';
          return `<tr ${trAttr}><td>${i+1}</td>
          <td style="font-weight:${isZeta?700:400}">${(LOOKUPS.corps[x.c]||'').substring(0,22)}${isZeta?' ⭐':''}</td>
          <td>${prodPills(x.c,2,false)}</td>
          <td><span class="badge badge-down">${x.shareChgPp.toFixed(2)}pp</span></td>
          <td>${fmtGrowth(x.gr)}</td></tr>`;
        }).join('')}
        </tbody>
      </table></div>
    </div>
  </div>

  <!-- Intelligence Commentary -->
  <div class="commentary">
    <h4>🧠 Competitive Intelligence — ${rangeLabel} Summary</h4>
    ${zetaRankNarr?`<p>${zetaRankNarr}</p>`:''}
    ${shareFlowNarrative?`<p>${shareFlowNarrative}</p>`:''}
    ${outgrowZeta.length>0?`<p><strong>${outgrowZeta.length} competitor${outgrowZeta.length>1?'s':''}</strong> outgrowing Zeta (excl. launch-boosted): ${outgrowZeta.slice(0,4).map(x=>`${(LOOKUPS.corps[x.c]||'').substring(0,16)} (EVI ${x.EVI})`).join(', ')}${outgrowZeta.length>4?' + more':''} — monitor closely.</p>`:'<p>✅ No non-launch-boosted competitor is outgrowing Zeta in the selected period.</p>'}
    ${newEntrants>0?`<p>🆕 <strong>${newEntrants} new market entrant${newEntrants>1?'s':''}</strong> detected: ${allCorps.filter(x=>x.isNew).slice(0,3).map(x=>(LOOKUPS.corps[x.c]||'').substring(0,16)).join(', ')}${newEntrants>3?' + more':''}. Monitor trajectory.</p>`:''}
    ${allCorps.filter(x=>x.isLaunch&&x.c!==ZETA_IDX).length>0?`<p>⚠️ <strong>${allCorps.filter(x=>x.isLaunch&&x.c!==ZETA_IDX).length} corp${allCorps.filter(x=>x.isLaunch&&x.c!==ZETA_IDX).length>1?'s':''}</strong> showing launch-boosted growth (>800% growth, near-zero prior period) — excluded from threat EVI calculations: ${allCorps.filter(x=>x.isLaunch&&x.c!==ZETA_IDX).slice(0,3).map(x=>(LOOKUPS.corps[x.c]||'').substring(0,14)).join(', ')}.</p>`:''}
    <p>Market structure: <strong>${fragLabel}</strong> (HHI ${Math.round(hhi)}) | Top-3 hold ${fmtPct(top3Share)} of market. ${hhi>2500?'High concentration — limited room for new players.':hhi>1500?'Moderate concentration — competitive dynamics active.':'Fragmented market — significant opportunity for share gains.'}</p>
  </div>`;

  document.getElementById('s-zeta-comp').innerHTML = aiInsightStrip('s-zeta-comp') + h;

  // ── Charts ────────────────────────────────────────────────────────────
  // 1. Competitive bar — top 15
  const top15 = allCorps.slice(0,15);
  barChart('ch-zci-bar',
    top15.map(x=>(LOOKUPS.corps[x.c]||'').substring(0,13)),
    [{label:ml,
      data: top15.map(x=>x.cur),
      colors: top15.map(x=>x.c===ZETA_IDX?'rgba(151,117,250,.9)':x.EVI>=110&&!x.isLaunch?'rgba(255,92,107,.7)':'rgba(76,110,245,.55)')}]);

  // 2. Growth rate horizontal — top 20 corps (non-zero prev)
  const grCorps = allCorps.filter(x=>x.prev>0).slice(0,20);
  const mktGrPct = (mktGr*100);
  hBarChart('ch-zci-gr',
    grCorps.map(x=>{
      const n=(LOOKUPS.corps[x.c]||'').substring(0,18);
      return x.isLaunch?n+' 🚀':x.c===ZETA_IDX?n+' ⭐':n;
    }),
    grCorps.map(x=>+(x.gr*100).toFixed(1)),
    grCorps.map(x=>{
      if(x.c===ZETA_IDX) return 'rgba(151,117,250,.9)';
      if(x.isLaunch)     return 'rgba(255,200,0,.6)';
      if(x.EVI>=110)     return 'rgba(255,92,107,.8)';
      if(x.gr>=0)        return 'rgba(76,110,245,.6)';
      return 'rgba(255,159,69,.6)';
    }),
    {
      _pct:true,
      plugins:{
        annotation:{
          annotations:{
            mktLine:{type:'line',xMin:mktGrPct,xMax:mktGrPct,
              borderColor:'rgba(54,201,148,.8)',borderWidth:2,borderDash:[4,3],
              label:{content:'Market avg',display:true,color:'#36c994',font:{size:9}}}
          }
        }
      }
    });

  // 3. 24M trend lines
  lineChart('ch-zci-trend',
    trendP.map(i=>P[i]),
    topCompsForTrend.map((x,ci)=>({
      label: (LOOKUPS.corps[x.c]||'').substring(0,14)+(x.c===ZETA_IDX?' ⭐':''),
      data:  trendP.map(t=>MV(monthlyCorps.get(t)?.get(x.c)||{lcv:0,su:0})),
      color: TREND_COLORS[ci],
      fill:  false,
      dashed: x.c!==ZETA_IDX
    })));

  // 4. Share delta waterfall — top 12 movers (by absolute share change)
  const shareMovers = allCorps.filter(x=>x.prev>0)
    .sort((a,b)=>Math.abs(b.shareChgPp)-Math.abs(a.shareChgPp)).slice(0,12)
    .sort((a,b)=>b.shareChgPp-a.shareChgPp);
  hBarChart('ch-zci-share',
    shareMovers.map(x=>{
      const n=(LOOKUPS.corps[x.c]||'').substring(0,18);
      return x.c===ZETA_IDX?n+' ⭐':n;
    }),
    shareMovers.map(x=>+x.shareChgPp.toFixed(2)),
    shareMovers.map(x=>x.c===ZETA_IDX?'rgba(151,117,250,.9)':x.shareChgPp>=0?'rgba(54,201,148,.75)':'rgba(255,92,107,.75)'),
    {_pct:true});

  makeSortable('tbl-zci');
}

function renderWinners() {
  const curPidxs=getPeriodIndices(STATE.timeRange);
  const prevPidxs=getPrevPeriodIndices(STATE.timeRange);
  const ml=STATE.metric.toUpperCase();
  const rangeLabel={mat:'MAT',ytd:'YTD',curr:'Month',all:'All','3m':'3M','6m':'6M'}[STATE.timeRange]||STATE.timeRange;
  const N=flat.length;
  const filterFn=dimFilter();

  // ── Filter context label ───────────────────────────────────────────────────
  const _ctxParts=[];
  if(STATE.fCorpSel.size>0) _ctxParts.push('Corp: '+[...STATE.fCorpSel].map(i=>LOOKUPS.corps[i]||i).join(', '));
  if(STATE.fDm1Sel.size>0)  _ctxParts.push('Market: '+[...STATE.fDm1Sel].map(i=>LOOKUPS.dm1s[i]||i).join(', '));
  if(STATE.fAtc4Sel.size>0) _ctxParts.push('ATC4: '+[...STATE.fAtc4Sel].map(i=>(LOOKUPS.atc4s[i]||i).substring(0,16)).join(', '));
  if(STATE.fDm2Sel.size>0)  _ctxParts.push('DM2: '+[...STATE.fDm2Sel].map(i=>LOOKUPS.dm2s[i]||i).join(', '));
  if(STATE.fBuSel.size>0)   _ctxParts.push('BU: '+[...STATE.fBuSel].map(i=>LOOKUPS.bus[i]||i).join(', '));
  if(STATE.fLineSel.size>0) _ctxParts.push('Line: '+[...STATE.fLineSel].map(i=>LOOKUPS.lines[i]||i).join(', '));
  const ctxLabel=_ctxParts.length>0?' · '+_ctxParts.join(' | '):'';

  // ── Corp-level ────────────────────────────────────────────────────────────
  const corpCur=aggBy(CI,filterFn,curPidxs), corpPrev=aggBy(CI,filterFn,prevPidxs);
  let totalCur=0,totalPrev=0;
  corpCur.forEach(v=>totalCur+=MV(v)); corpPrev.forEach(v=>totalPrev+=MV(v));

  const corps=[...corpCur.entries()].map(([c,v])=>{
    const pv=corpPrev.get(c)||{lcv:0,su:0};
    return {c,lcv:v.lcv,su:v.su,prevLcv:pv.lcv,prevSu:pv.su,
      growth:growth(MV(v),MV(pv)),
      share:totalCur>0?MV(v)/totalCur:0,
      prevShare:totalPrev>0?MV(pv)/totalPrev:0,
      shareChange:totalCur>0&&totalPrev>0?(MV(v)/totalCur)-(MV(pv)/totalPrev):0};
  }).filter(x=>MV(x)>0||x.prevLcv>0||x.prevSu>0);

  const prevCorpRanks=[...corpPrev.entries()].sort((a,b)=>MV(b[1])-MV(a[1]));
  const prevCorpRankMap=new Map(prevCorpRanks.map(([c],i)=>[c,i+1]));
  const curCorpRanks=[...corpCur.entries()].sort((a,b)=>MV(b[1])-MV(a[1]));
  const curCorpRankMap=new Map(curCorpRanks.map(([c],i)=>[c,i+1]));
  corps.forEach(c=>{
    c.curRank=curCorpRankMap.get(c.c)||99;
    c.prevRank=prevCorpRankMap.get(c.c)||99;
    c.rankChange=c.prevRank-c.curRank;
  });

  const corpGainers=corps.filter(c=>c.shareChange>0).sort((a,b)=>b.shareChange-a.shareChange).slice(0,10);
  const corpLosers=corps.filter(c=>c.shareChange<0).sort((a,b)=>a.shareChange-b.shareChange).slice(0,10);
  const rankClimbers=corps.filter(c=>c.rankChange>0).sort((a,b)=>b.rankChange-a.rankChange).slice(0,10);
  const rankFallers=corps.filter(c=>c.rankChange<0).sort((a,b)=>a.rankChange-b.rankChange).slice(0,10);

  // ── Product-level ─────────────────────────────────────────────────────────
  // Build product → primary corp map (highest LCV in MAT)
  const prodCorpLcv=new Map(); // prodIdx -> Map(corpIdx->lcv)
  for(let i=0;i<N;i+=10){
    if(!curPidxs.has(flat[i+2])) continue;
    if(filterFn && !filterFn(flat[i],flat[i+1],flat[i+2],flat[i+3],flat[i+4],flat[i+5],flat[i+LINEI],flat[i+BUCI])) continue;
    const p=flat[i+1],c=flat[i],lcv=flat[i+6];
    if(!prodCorpLcv.has(p)) prodCorpLcv.set(p,new Map());
    const m=prodCorpLcv.get(p);
    m.set(c,(m.get(c)||0)+lcv);
  }
  const prodPrimaryCorpMap=new Map();
  prodCorpLcv.forEach((m,p)=>{
    let bestC=-1,bestV=0;
    m.forEach((v,c)=>{ if(v>bestV){bestV=v;bestC=c;} });
    prodPrimaryCorpMap.set(p,bestC);
  });

  const prodCur=aggBy(PI,filterFn,curPidxs);
  const prodPrev=aggBy(PI,filterFn,prevPidxs);
  let ptotalCur=0,ptotalPrev=0;
  prodCur.forEach(v=>ptotalCur+=MV(v));
  prodPrev.forEach(v=>ptotalPrev+=MV(v));

  const prods=[...prodCur.entries()].map(([p,v])=>{
    const pv=prodPrev.get(p)||{lcv:0,su:0};
    const corp=prodPrimaryCorpMap.get(p)??-1;
    const corpLabel=LOOKUPS.corps[corp]||'?';
    const prodLabel=LOOKUPS.prods[p]||'';
    return {p,corp,corpLabel,prodLabel,
      label:`${prodLabel.substring(0,20)} (${corpLabel.substring(0,14)})`,
      lcv:v.lcv,su:v.su,prevLcv:pv.lcv,prevSu:pv.su,
      growth:growth(MV(v),MV(pv)),
      share:ptotalCur>0?MV(v)/ptotalCur:0,
      prevShare:ptotalPrev>0?MV(pv)/ptotalPrev:0,
      shareChange:ptotalCur>0&&ptotalPrev>0?(MV(v)/ptotalCur)-(MV(pv)/ptotalPrev):0,
      incr:MV(v)-(STATE.metric==='lcv'?pv.lcv:pv.su)};
  }).filter(x=>MV(x)>0||x.prevLcv>0||x.prevSu>0);

  const prevProdRanks=[...prodPrev.entries()].sort((a,b)=>MV(b[1])-MV(a[1]));
  const prevProdRankMap=new Map(prevProdRanks.map(([p],i)=>[p,i+1]));
  const curProdRanks=[...prodCur.entries()].sort((a,b)=>MV(b[1])-MV(a[1]));
  const curProdRankMap=new Map(curProdRanks.map(([p],i)=>[p,i+1]));
  prods.forEach(p=>{
    p.curRank=curProdRankMap.get(p.p)||9999;
    p.prevRank=prevProdRankMap.get(p.p)||9999;
    p.rankChange=p.prevRank-p.curRank;
  });

  const prodGainers=prods.filter(p=>p.shareChange>0).sort((a,b)=>b.shareChange-a.shareChange).slice(0,10);
  const prodLosers=prods.filter(p=>p.shareChange<0).sort((a,b)=>a.shareChange-b.shareChange).slice(0,10);
  const prodClimbers=prods.filter(p=>p.rankChange>0).sort((a,b)=>b.rankChange-a.rankChange).slice(0,10);
  const prodFallers=prods.filter(p=>p.rankChange<0).sort((a,b)=>a.rankChange-b.rankChange).slice(0,10);

  // ── HTML ─────────────────────────────────────────────────────────────────
  const html=`
  <div class="section-title">🏆 Winners & Losers Center</div>
  <div class="section-sub">Share gainers, rank climbers & market dynamics — ${rangeLabel} | ${ml}${ctxLabel}</div>

  <!-- ═══ CORPORATION LEVEL ═══ -->
  <div style="font-size:11px;font-weight:700;color:var(--txt2);margin:10px 0 4px;letter-spacing:.08em">🏢 CORPORATION LEVEL</div>

  <div class="chart-row cols2">
    <div class="chart-box">
      <div class="chart-box-title">📈 Top Corp Share Gainers</div>
      <div class="chart-wrap" style="height:240px"><canvas id="ch-wl-gain"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">📉 Top Corp Share Losers</div>
      <div class="chart-wrap" style="height:240px"><canvas id="ch-wl-lose"></canvas></div>
    </div>
  </div>

  <div class="two-col">
    <div class="tbl-wrap">
      <div class="tbl-head"><span class="tbl-head-title">🚀 Corp Rank Climbers</span></div>
      <div class="tbl-scroll"><table><thead><tr><th>Corporation</th><th>Rank Δ</th><th>Rank Now</th><th>Growth</th></tr></thead><tbody>
      ${rankClimbers.map(c=>`<tr>
        <td style="font-weight:500">${LOOKUPS.corps[c.c]||''}</td>
        <td><span class="badge badge-up">▲${c.rankChange}</span></td>
        <td>#${c.curRank}</td><td>${fmtGrowth(c.growth)}</td></tr>`).join('')}
      </tbody></table></div>
    </div>
    <div class="tbl-wrap">
      <div class="tbl-head"><span class="tbl-head-title">📉 Corp Rank Fallers</span></div>
      <div class="tbl-scroll"><table><thead><tr><th>Corporation</th><th>Rank Δ</th><th>Rank Now</th><th>Growth</th></tr></thead><tbody>
      ${rankFallers.map(c=>`<tr>
        <td style="font-weight:500">${LOOKUPS.corps[c.c]||''}</td>
        <td><span class="badge badge-down">▼${Math.abs(c.rankChange)}</span></td>
        <td>#${c.curRank}</td><td>${fmtGrowth(c.growth)}</td></tr>`).join('')}
      </tbody></table></div>
    </div>
  </div>

  <div class="tbl-wrap">
    <div class="tbl-head">
      <span class="tbl-head-title">Full Corporation Share Analysis</span>
      <input class="tbl-search" placeholder="Search corp..." oninput="filterTbl(this,'tbl-wl-body')">
    </div>
    <div class="tbl-scroll"><table id="tbl-wl"><thead><tr>
      <th>Corporation</th><th>Rank Now</th><th>Rank Before</th><th>Rank Δ</th>
      <th>Share Now</th><th>Share Before</th><th>Share Δ</th><th>Growth</th>
    </tr></thead><tbody id="tbl-wl-body">
    ${corps.sort((a,b)=>a.curRank-b.curRank).map(c=>`<tr>
      <td style="font-weight:500">${LOOKUPS.corps[c.c]||''}</td>
      <td>#${c.curRank}</td><td>#${c.prevRank}</td>
      <td><span class="badge ${c.rankChange>0?'badge-up':c.rankChange<0?'badge-down':'badge-neutral'}">${c.rankChange>0?'▲'+c.rankChange:c.rankChange<0?'▼'+Math.abs(c.rankChange):'—'}</span></td>
      <td>${fmtPct(c.share)}</td><td>${fmtPct(c.prevShare)}</td>
      <td><span class="badge ${c.shareChange>0?'badge-up':c.shareChange<0?'badge-down':'badge-neutral'}">${(c.shareChange*100).toFixed(2)}pp</span></td>
      <td>${fmtGrowth(c.growth)}</td>
    </tr>`).join('')}
    </tbody></table></div>
  </div>

  <!-- ═══ PRODUCT LEVEL ═══ -->
  <div style="font-size:11px;font-weight:700;color:var(--txt2);margin:18px 0 4px;letter-spacing:.08em">💊 PRODUCT LEVEL</div>

  <div class="chart-row cols2">
    <div class="chart-box">
      <div class="chart-box-title">📈 Top Product Share Gainers
        <span class="chart-box-sub">Product (Corp)</span></div>
      <div class="chart-wrap" style="height:260px"><canvas id="ch-wl-pgain"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">📉 Top Product Share Losers
        <span class="chart-box-sub">Product (Corp)</span></div>
      <div class="chart-wrap" style="height:260px"><canvas id="ch-wl-plose"></canvas></div>
    </div>
  </div>

  <div class="two-col">
    <div class="tbl-wrap">
      <div class="tbl-head"><span class="tbl-head-title">🚀 Product Rank Climbers</span></div>
      <div class="tbl-scroll"><table><thead><tr><th>Product</th><th>Corporation</th><th>Rank Δ</th><th>Rank Now</th><th>Growth</th></tr></thead><tbody>
      ${prodClimbers.map(p=>`<tr>
        <td style="font-weight:500">${p.prodLabel}</td>
        <td style="color:var(--txt2);font-size:11px">${p.corpLabel}</td>
        <td><span class="badge badge-up">▲${p.rankChange}</span></td>
        <td>#${p.curRank}</td><td>${fmtGrowth(p.growth)}</td></tr>`).join('')}
      </tbody></table></div>
    </div>
    <div class="tbl-wrap">
      <div class="tbl-head"><span class="tbl-head-title">📉 Product Rank Fallers</span></div>
      <div class="tbl-scroll"><table><thead><tr><th>Product</th><th>Corporation</th><th>Rank Δ</th><th>Rank Now</th><th>Growth</th></tr></thead><tbody>
      ${prodFallers.map(p=>`<tr>
        <td style="font-weight:500">${p.prodLabel}</td>
        <td style="color:var(--txt2);font-size:11px">${p.corpLabel}</td>
        <td><span class="badge badge-down">▼${Math.abs(p.rankChange)}</span></td>
        <td>#${p.curRank}</td><td>${fmtGrowth(p.growth)}</td></tr>`).join('')}
      </tbody></table></div>
    </div>
  </div>

  <div class="tbl-wrap">
    <div class="tbl-head">
      <span class="tbl-head-title">Full Product Share Analysis — Product (Corporation)</span>
      <input class="tbl-search" placeholder="Search product or corp..." oninput="filterTbl(this,'tbl-wl-prod-body')">
    </div>
    <div class="tbl-scroll"><table id="tbl-wl-prod"><thead><tr>
      <th>Product</th><th>Corporation</th><th>Rank Now</th><th>Rank Before</th><th>Rank Δ</th>
      <th>Share Now</th><th>Share Δ</th><th>Growth</th><th>Incremental ${ml}</th>
    </tr></thead><tbody id="tbl-wl-prod-body">
    ${prods.sort((a,b)=>a.curRank-b.curRank).slice(0,50).map(p=>`<tr>
      <td style="font-weight:500">${p.prodLabel}</td>
      <td style="color:var(--acc1);font-size:11px;font-weight:500">${p.corpLabel}</td>
      <td>#${p.curRank}</td><td>#${p.prevRank}</td>
      <td><span class="badge ${p.rankChange>0?'badge-up':p.rankChange<0?'badge-down':'badge-neutral'}">${p.rankChange>0?'▲'+p.rankChange:p.rankChange<0?'▼'+Math.abs(p.rankChange):'—'}</span></td>
      <td>${fmtPct(p.share)}</td>
      <td><span class="badge ${p.shareChange>0?'badge-up':p.shareChange<0?'badge-down':'badge-neutral'}">${(p.shareChange*100).toFixed(2)}pp</span></td>
      <td>${fmtGrowth(p.growth)}</td>
      <td><span class="badge ${p.incr>=0?'badge-up':'badge-down'}">${p.incr>=0?'+':''}${fmtLCV(p.incr)}</span></td>
    </tr>`).join('')}
    </tbody></table></div>
  </div>`;

  document.getElementById('s-winners').innerHTML = aiInsightStrip('s-winners') + html;

  // Corp charts
  barChart('ch-wl-gain',corpGainers.map(c=>LOOKUPS.corps[c.c].substring(0,16)),
    [{label:`${ml} Growth`,data:corpGainers.map(c=>MV(c)-(STATE.metric==='lcv'?c.prevLcv:c.prevSu)),
      colors:corpGainers.map(()=>'rgba(54,201,148,.8)')}]);
  barChart('ch-wl-lose',corpLosers.map(c=>LOOKUPS.corps[c.c].substring(0,16)),
    [{label:`${ml} Decline`,data:corpLosers.map(c=>MV(c)-(STATE.metric==='lcv'?c.prevLcv:c.prevSu)),
      colors:corpLosers.map(()=>'rgba(255,92,107,.8)')}]);

  // Product charts — combined "Prod (Corp)" label
  barChart('ch-wl-pgain',prodGainers.map(p=>p.label),
    [{label:`${ml} Incr`,data:prodGainers.map(p=>p.incr),
      colors:prodGainers.map(()=>'rgba(76,110,245,.8)')}]);
  barChart('ch-wl-plose',prodLosers.map(p=>p.label),
    [{label:`${ml} Decr`,data:prodLosers.map(p=>p.incr),
      colors:prodLosers.map(()=>'rgba(255,159,69,.8)')}]);

  makeSortable('tbl-wl');
  makeSortable('tbl-wl-prod');
}

// ===================== MARKET CONCENTRATION =====================
function computeGini(vals) {
  // vals = raw values (not pre-normalized). Returns 0 (equal) → ~1 (monopoly).
  var n=vals.length; if(!n) return 0;
  var sorted=[...vals].sort(function(a,b){return a-b;});
  var tot=sorted.reduce(function(s,v){return s+v;},0); if(!tot) return 0;
  var num=sorted.reduce(function(s,v,i){return s+(2*(i+1)-n-1)*v;},0);
  return Math.max(0,Math.min(1, num/(n*tot)));
}
function renderConcentration() {
  const SEC        = 's-concentration';
  const filterFn   = dimFilter();
  const curPidxs   = getPeriodIndices(STATE.timeRange);
  const prevPidxs  = getPrevPeriodIndices(STATE.timeRange);
  const ml         = STATE.metric==='lcv'?'LCV':'SU';
  const rangeLabel = {mat:'MAT',ytd:'YTD',curr:'Month',all:'All','3m':'3M','6m':'6M'}[STATE.timeRange]||STATE.timeRange;
  const N          = flat.length;

  // ── Filter context (abbreviated when many items selected) ────────────────
  const _abbrevCtx=(set,lookup,label,max)=>{
    if(!set||!set.size) return '';
    const names=[...set].map(i=>(lookup[i]||i));
    return label+': '+(names.length<=max?names.join(', '):names.length+' selected');
  };
  const _cp=[];
  const _cA=_abbrevCtx(STATE.fCorpSel,LOOKUPS.corps,'Corp',2);   if(_cA) _cp.push(_cA);
  const _mA=_abbrevCtx(STATE.fDm1Sel,LOOKUPS.dm1s,'Market',2);   if(_mA) _cp.push(_mA);
  const _bA=_abbrevCtx(STATE.fBuSel,LOOKUPS.bus,'BU',3);          if(_bA) _cp.push(_bA);
  const ctxLabel = _cp.length>0?' · '+_cp.join(' | '):'';

  // ── Build corp→metric maps per DM1 (cur + prev) — LCV or SU ─────────────
  const _MI = STATE.metric==='lcv' ? LI : SI;   // LI=6 (lcv), SI=7 (su)
  const buildDm1Map = pidxs => {
    const out = new Map();
    for(let i=0;i<N;i+=10){
      if(!pidxs.has(flat[i+2])) continue;
      if(filterFn && !filterFn(flat[i],flat[i+1],flat[i+2],flat[i+3],flat[i+4],flat[i+5],flat[i+LINEI],flat[i+BUCI])) continue;
      const c=flat[i], d1=flat[i+4], val=flat[i+_MI];
      if(!out.has(d1)) out.set(d1,new Map());
      const m=out.get(d1); m.set(c,(m.get(c)||0)+val);
    }
    return out;
  };
  const dm1CorpCur  = buildDm1Map(curPidxs);
  const dm1CorpPrev = buildDm1Map(prevPidxs);

  // ── Compute metrics per DM1 ───────────────────────────────────────────────
  const dm1HHI = [...dm1CorpCur.entries()].map(([d,corpMap])=>{
    const total    = [...corpMap.values()].reduce((s,v)=>s+v,0)||1;
    const sorted   = [...corpMap.entries()].sort((a,b)=>b[1]-a[1]);
    const hhi      = sorted.reduce((s,[,v])=>s+(v/total)*(v/total)*10000, 0);
    const cr1      = (sorted[0]?.[1]||0)/total;
    const cr4      = sorted.slice(0,4).reduce((s,[,v])=>s+v,0)/total;
    const cr5      = sorted.slice(0,5).reduce((s,[,v])=>s+v,0)/total;
    const gini     = computeGini(sorted.map(([,v])=>v));
    const domCorp  = sorted[0]?.[0]??-1;
    const domName  = (LOOKUPS.corps[domCorp]||'').substring(0,18);
    const zetaLcv  = corpMap.get(ZETA_IDX)||0;  // holds LCV or SU per STATE.metric
    const zetaShare= zetaLcv/total;
    const zetaRank = sorted.findIndex(([c])=>c===ZETA_IDX)+1||null;
    const effComp  = hhi>0 ? 10000/hhi : 0;
    const nCorps   = corpMap.size;
    // prev HHI
    const prevMap  = dm1CorpPrev.get(d)||new Map();
    const pt       = [...prevMap.values()].reduce((s,v)=>s+v,0)||1;
    const prevHhi  = [...prevMap.values()].reduce((s,v)=>s+(v/pt)*(v/pt)*10000, 0);
    const hhiDelta = Math.round(hhi-prevHhi);
    let struct='Competitive';
    if(hhi>1800) struct='Highly Concentrated';
    else if(hhi>1000) struct='Moderately Concentrated';
    return {d,hhi:Math.round(hhi),cr1,cr4,cr5,gini,domCorp,domName,zetaShare,zetaRank,
            effComp,nCorps,total,struct,hhiDelta,zetaLcv};
  }).filter(x=>x.zetaLcv>0).sort((a,b)=>b.total-a.total);

  // ── KPI summary ───────────────────────────────────────────────────────────
  const _totW       = dm1HHI.reduce((s,x)=>s+x.total,0)||1;
  const weightedHHI = dm1HHI.reduce((s,x)=>s+x.hhi*x.total,0) / _totW;
  const avgCr4      = dm1HHI.reduce((s,x)=>s+x.cr4*x.total,0) / _totW;
  const avgGini     = dm1HHI.reduce((s,x)=>s+x.gini*x.total,0) / _totW;
  const highlyConc  = dm1HHI.filter(x=>x.struct==='Highly Concentrated').length;
  const competitive = dm1HHI.filter(x=>x.struct==='Competitive').length;
  const zetaLeads   = dm1HHI.filter(x=>x.zetaRank===1).length;
  const zetaTop3    = dm1HHI.filter(x=>x.zetaRank&&x.zetaRank<=3).length;
  const concIncr    = dm1HHI.filter(x=>x.hhiDelta>50).length;

  // ── Dynamic insights ──────────────────────────────────────────────────────
  const oppMkts  = dm1HHI.filter(x=>x.struct==='Competitive'&&x.zetaShare<0.15&&x.total>0).slice(0,3);
  const leadMkts = dm1HHI.filter(x=>x.zetaRank===1).slice(0,3);
  const riskMkts = dm1HHI.filter(x=>x.struct==='Highly Concentrated'&&x.zetaRank&&x.zetaRank>3).slice(0,3);
  const _dn = d=>(LOOKUPS.dm1s[d]||'').substring(0,22);

  const insightLines=[];
  if(zetaLeads>0)
    insightLines.push(`<span style="color:#2fc97e;font-weight:700">👑 Zeta leads</span> in <b>${zetaLeads}</b> market${zetaLeads>1?'s':''}: ${leadMkts.map(x=>`<b>${_dn(x.d)}</b> (${fmtPct(x.zetaShare)} share)`).join(' · ')}.`);
  if(oppMkts.length>0)
    insightLines.push(`<span style="color:#4c6ef5;font-weight:700">🎯 Entry opportunity</span> — Competitive markets with low Zeta penetration: ${oppMkts.map(x=>`<b>${_dn(x.d)}</b> (HHI ${x.hhi}, Zeta ${fmtPct(x.zetaShare)})`).join(' · ')}.`);
  if(riskMkts.length>0)
    insightLines.push(`<span style="color:#e05c5c;font-weight:700">🚫 Dominated markets</span> — Highly concentrated, Zeta rank >3: ${riskMkts.map(x=>`<b>${_dn(x.d)}</b> (${x.domName} owns ${fmtPct(x.cr1)})`).join(' · ')}.`);
  if(concIncr>0)
    insightLines.push(`<span style="color:#ffb800;font-weight:700">📈 Consolidating</span> — HHI rising (>50pts) in <b>${concIncr}</b> markets — watch for emerging dominant players.`);
  insightLines.push(`<span style="color:var(--txt2);font-weight:700">📊 Portfolio summary</span> — Zeta in top-3 in <b>${zetaTop3}</b> markets; weighted avg HHI <b>${Math.round(weightedHHI)}</b> (${weightedHHI>1800?'highly concentrated':weightedHHI>1000?'moderately concentrated':'competitive'} landscape).`);

  const insightHTML=`<div class="commentary" style="margin-bottom:16px;border-left:3px solid var(--acc1);padding:2px 0 2px 14px">
    <div style="font-size:10.5px;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.6px;margin-bottom:7px">⚡ Competitive Structure Insights — ${rangeLabel}${ctxLabel}</div>
    ${insightLines.map(l=>`<p style="font-size:12.5px;line-height:1.6;margin-bottom:4px">${l}</p>`).join('')}
  </div>`;

  // ── HTML ──────────────────────────────────────────────────────────────────
  const kpi=(label,val,sub,card='blue')=>`<div class="kpi-card ${card}"><div class="kpi-label">${label}</div><div class="kpi-value">${val}</div><div class="kpi-sub">${sub}</div></div>`;
  const pageHtml=`
  <div class="section-title">📐 Market Concentration Analysis</div>
  <div class="section-sub">Market Concentration (HHI) · CR4 · Market Balance (Gini) · Zeta Position — ${rangeLabel}${ctxLabel}</div>

  <div class="kpi-grid" style="grid-template-columns:repeat(5,1fr);margin-bottom:16px">
    ${kpi('Mkt Concentration', Math.round(weightedHHI), weightedHHI>1800?'Highly Concentrated':weightedHHI>1000?'Moderate':'Competitive', weightedHHI>1800?'red':weightedHHI>1000?'orange':'green')}
    ${kpi('High Conc. Markets', highlyConc+' / '+dm1HHI.length, 'HHI > 1800 — monopolistic risk', highlyConc>0?'red':'green')}
    ${kpi('Avg CR4', fmtPct(avgCr4), 'Top 4 corps — wtd avg share', avgCr4>0.8?'red':avgCr4>0.5?'orange':'green')}
    ${kpi('Market Balance', avgGini.toFixed(2), avgGini>0.6?'Imbalanced':avgGini>0.3?'Moderate':'Balanced', avgGini>0.6?'red':avgGini>0.3?'orange':'green')}
    ${kpi('Zeta Leads', zetaLeads+' markets', 'Top-3 in '+zetaTop3+' markets', zetaLeads>0?'green':'orange')}
  </div>

  ${insightHTML}

  <div class="chart-row cols2">
    <div class="chart-box">
      <div class="chart-box-title">Market Concentration (HHI) — Top 15
        <span class="chart-box-sub">🔴 > 1800 Dominated · 🟡 1000–1800 Moderate · 🟢 &lt; 1000 Competitive</span></div>
      <div class="chart-wrap" style="height:320px"><canvas id="ch-conc-hhi"></canvas></div>
    </div>
    <div class="chart-box">
      <div class="chart-box-title">Strategic Position Matrix
        <span class="chart-box-sub">Bubble = Market Size · Quadrants guide resource allocation</span></div>
      <div class="chart-wrap" style="height:320px"><canvas id="ch-conc-scatter"></canvas></div>
    </div>
  </div>

  <div class="tbl-wrap" style="margin-top:16px">
    <div class="tbl-head"><span class="tbl-head-title">📋 Full Market Concentration Detail</span>
      <span style="font-size:11px;color:var(--txt3);margin-left:10px">Click any row for plain-language interpretation · Hover <b>?</b> on headers for metric guide</span>
    </div>
    <div class="tbl-scroll"><table id="tbl-conc"><thead><tr>
      <th>#</th>
      <th>Defined Market</th>
      <th><span class="th-tip">HHI <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>Market Concentration (HHI)</b>Sum of squared shares × 10,000. Higher = fewer players dominate.
          <div class="tip-row"><span class="tip-dot tip-green"></span>&lt; 1,000 — Competitive, easy to grow</div>
          <div class="tip-row"><span class="tip-dot tip-amber"></span>1,000–1,800 — Moderate concentration</div>
          <div class="tip-row"><span class="tip-dot tip-red"></span>&gt; 1,800 — Dominated, hard to enter</div>
        </div></span>
      </th>
      <th><span class="th-tip">Δ <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>HHI Change vs prior period</b>Rising = market consolidating (competitor pulling away). Falling = market opening up.
          <div class="tip-row"><span class="tip-dot tip-red"></span>+50 pts — consolidating fast, act now</div>
          <div class="tip-row"><span class="tip-dot tip-green"></span>−50 pts — opening up, opportunity window</div>
        </div></span>
      </th>
      <th><span class="th-tip">CR1 <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>CR1 — Top 1 company share</b>Single largest competitor's market share.
          <div class="tip-row"><span class="tip-dot tip-green"></span>&lt; 30% — no monopolist present</div>
          <div class="tip-row"><span class="tip-dot tip-red"></span>&gt; 60% — one company owns the market</div>
        </div></span>
      </th>
      <th><span class="th-tip">CR4 <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>CR4 — Top 4 combined share</b>Standard pharma competitive intensity benchmark.
          <div class="tip-row"><span class="tip-dot tip-green"></span>&lt; 50% — open, no cartel</div>
          <div class="tip-row"><span class="tip-dot tip-amber"></span>50–80% — concentrated but contestable</div>
          <div class="tip-row"><span class="tip-dot tip-red"></span>&gt; 80% — top 4 locked in, little room</div>
        </div></span>
      </th>
      <th>CR5</th>
      <th><span class="th-tip">Market Balance <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>Gini coefficient</b>How evenly shares are spread across all players. 0.00 = all equal. 1.00 = one company takes everything.
          <div class="tip-row"><span class="tip-dot tip-green"></span>&lt; 0.30 — Balanced, fair competition</div>
          <div class="tip-row"><span class="tip-dot tip-amber"></span>0.30–0.60 — Moderate skew</div>
          <div class="tip-row"><span class="tip-dot tip-red"></span>&gt; 0.60 — Severe imbalance</div>
        </div></span>
      </th>
      <th>Dominant Corp</th>
      <th><span class="th-tip">Eff. Comp <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>Effective Competition = 10,000 ÷ HHI</b>Equivalent number of equal-sized competitors the market behaves like.
          <div class="tip-row"><span class="tip-dot tip-green"></span>&gt; 10 — highly fragmented market</div>
          <div class="tip-row"><span class="tip-dot tip-red"></span>&lt; 3 — behaves like a duopoly</div>
        </div></span>
      </th>
      <th><span class="th-tip">Zeta Share <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>Zeta's market share in this DM1</b>Zeta sales ÷ total market sales.
          <div class="tip-row"><span class="tip-dot tip-green"></span>≥ 30% — strong, market leader territory</div>
          <div class="tip-row"><span class="tip-dot tip-amber"></span>15–29% — contender, viable position</div>
          <div class="tip-row"><span class="tip-dot tip-red"></span>&lt; 15% — marginal, low strategic leverage</div>
        </div></span>
      </th>
      <th><span class="th-tip">Zeta Rank <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>Zeta's rank by sales among all corporations in this market</b>#1 = market leader. Read together with HHI — rank #2 in HHI 2000 market means Zeta IS the dominant player.</div></span>
      </th>
      <th>Structure</th>
      <th><span class="th-tip">Action <span class="th-tip-icon">?</span>
        <div class="tip-box"><b>Strategic Action — derived from HHI + Zeta rank</b>
          <div class="tip-row"><span style="color:#2fc97e;font-weight:600">ACCELERATE</span> — Low HHI, Zeta #1–2. You lead a competitive market. Widen the gap.</div>
          <div class="tip-row"><span style="color:var(--acc1);font-weight:600">GROW</span> — Low HHI, Zeta #3+. Market is open but Zeta underperforming. Invest.</div>
          <div class="tip-row"><span style="color:#ffb800;font-weight:600">DEFEND</span> — High HHI, Zeta #1–2. You are the dominant player. Protect your lead.</div>
          <div class="tip-row"><span style="color:#e05c5c;font-weight:600">DEPRIORITIZE</span> — High HHI, Zeta #3+. Dominated by others. Redirect resources.</div>
        </div></span>
      </th>
    </tr></thead><tbody>
    ${dm1HHI.map((x,i)=>{
      // ── Strategic action logic ─────────────────────────────────────────────
      const isHighConc = x.hhi >= 1800;
      const isMod      = x.hhi >= 1000 && x.hhi < 1800;
      const zetaTop2   = x.zetaRank && x.zetaRank <= 2;
      let action, acCls, acIcon;
      if(!isHighConc && !isMod && zetaTop2)  { action='ACCELERATE'; acCls='ac-accel';  acIcon='🚀'; }
      else if(!isHighConc && !isMod)          { action='GROW';        acCls='ac-grow';   acIcon='🎯'; }
      else if(isHighConc && zetaTop2)         { action='DEFEND';      acCls='ac-defend'; acIcon='🛡'; }
      else if(isHighConc && !zetaTop2)        { action='DEPRIORITIZE';acCls='ac-deprio'; acIcon='⬇'; }
      else if(isMod && zetaTop2)              { action='DEFEND';      acCls='ac-defend'; acIcon='🛡'; }
      else                                    { action='GROW';        acCls='ac-grow';   acIcon='🎯'; }

      // ── Plain-language interpretation ──────────────────────────────────────
      const mktName  = (LOOKUPS.dm1s[x.d]||'').substring(0,28);
      const effStr   = x.effComp.toFixed(1);
      const zetaPct  = fmtPct(x.zetaShare);
      const cr4Pct   = fmtPct(x.cr4);
      const rankStr  = x.zetaRank ? '#'+x.zetaRank : 'unranked';
      const deltaStr = x.hhiDelta >= 0 ? `rising +${x.hhiDelta} pts (consolidating — watch for a dominant player emerging)` : `falling ${x.hhiDelta} pts (opening up — opportunity window)`;
      let interp = '';
      if(action==='ACCELERATE')
        interp = `<b style="color:#2fc97e">🚀 ACCELERATE</b> — ${mktName} is a competitive market (HHI ${x.hhi}, ${effStr} effective competitors). Zeta holds ${zetaPct} share at ${rankStr} — you lead this market. CR4 is ${cr4Pct}. Priority: push harder to widen the gap before a challenger consolidates. HHI is ${deltaStr}.`;
      else if(action==='GROW')
        interp = `<b style="color:var(--acc1)">🎯 GROW</b> — ${mktName} is a competitive, open market (HHI ${x.hhi}, ${effStr} effective competitors) but Zeta is only ${rankStr} at ${zetaPct} share. The market is winnable — investigate what is holding Zeta back and invest in field force or patient access. HHI is ${deltaStr}.`;
      else if(action==='DEFEND')
        interp = `<b style="color:#ffb800">🛡 DEFEND</b> — ${mktName} is concentrated (HHI ${x.hhi}) and Zeta holds ${zetaPct} at ${rankStr} — you are the dominant or near-dominant player. CR4 = ${cr4Pct}. Do not underinvest; challengers will target you. Monitor Δ HHI closely. HHI is ${deltaStr}.`;
      else
        interp = `<b style="color:#e05c5c">⬇ DEPRIORITIZE</b> — ${mktName} is highly concentrated (HHI ${x.hhi}) and Zeta is only ${rankStr} at ${zetaPct} share. ${x.domName} dominates with CR4 = ${cr4Pct}. Fighting for share here has low ROI. Maintain minimal presence; redirect field force investment to GROW or ACCELERATE markets. HHI is ${deltaStr}.`;

      const rowId = 'conc-exp-'+i;
      const bgAccent = action==='ACCELERATE'?'rgba(47,201,126,.08)':action==='GROW'?'rgba(76,110,245,.08)':action==='DEFEND'?'rgba(255,159,69,.08)':'rgba(255,92,107,.08)';
      const borderCol = action==='ACCELERATE'?'#2fc97e':action==='GROW'?'var(--acc1)':action==='DEFEND'?'#ffb800':'#e05c5c';

      return `<tr class="conc-row-clickable" onclick="concToggle('${rowId}')" style="border-left:3px solid ${borderCol}">
        <td><span class="rank-badge ${i<3?'top3':''}">${i+1}</span></td>
        <td style="max-width:130px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${LOOKUPS.dm1s[x.d]||''}">${mktName}</td>
        <td style="font-weight:700;${x.hhi>1800?'color:#e05c5c':x.hhi>1000?'color:#ffb800':'color:#2fc97e'}">${x.hhi}</td>
        <td style="${x.hhiDelta>50?'color:#e05c5c':x.hhiDelta<-50?'color:#2fc97e':'color:var(--txt3)'}">${x.hhiDelta>=0?'+':''}${x.hhiDelta}</td>
        <td>${fmtPct(x.cr1)}</td>
        <td style="font-weight:600">${fmtPct(x.cr4)}</td>
        <td>${fmtPct(x.cr5)}</td>
        <td style="${x.gini>0.6?'color:#e05c5c':x.gini>0.3?'color:#ffb800':'color:#2fc97e'};font-weight:600">${x.gini.toFixed(2)}
          <span style="font-size:10px;color:var(--txt3)">${x.gini>0.6?'Imbalanced':x.gini>0.3?'Moderate':'Balanced'}</span></td>
        <td style="font-size:11px;color:var(--txt2)">${x.domName}</td>
        <td>${x.effComp.toFixed(1)}</td>
        <td style="${x.zetaShare>=0.3?'color:#2fc97e':x.zetaShare>=0.15?'color:#ffb800':'color:#e05c5c'};font-weight:600">${zetaPct}</td>
        <td>${x.zetaRank?'#'+x.zetaRank:'—'}</td>
        <td><span class="badge ${x.struct==='Competitive'?'badge-up':x.struct==='Moderately Concentrated'?'badge-warn':'badge-down'}">${x.struct==='Highly Concentrated'?'High Conc.':x.struct==='Moderately Concentrated'?'Moderate':x.struct}</span></td>
        <td><span class="ac-chip ${acCls}">${acIcon} ${action}</span></td>
      </tr>
      <tr class="conc-expand-row" id="${rowId}">
        <td colspan="14"><div class="conc-expand-inner" style="background:${bgAccent};border-left:3px solid ${borderCol}">${interp}</div></td>
      </tr>`;
    }).join('')}
    </tbody></table></div>
  </div>

  <div style="margin-top:20px">
    <div style="font-size:10.5px;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.6px;margin-bottom:8px">📖 How to Read This Page</div>
    <div class="tbl-scroll"><table style="width:100%;font-size:11.5px;border-collapse:collapse;min-width:700px">
      <thead><tr style="background:rgba(255,255,255,.04)">
        <th style="padding:7px 10px;text-align:left;color:var(--txt3);font-weight:600;border-bottom:1px solid rgba(255,255,255,.08);white-space:nowrap">Metric</th>
        <th style="padding:7px 10px;text-align:left;color:var(--txt3);font-weight:600;border-bottom:1px solid rgba(255,255,255,.08)">What it tells you</th>
        <th style="padding:7px 10px;text-align:left;color:var(--txt3);font-weight:600;border-bottom:1px solid rgba(255,255,255,.08)">🟢 Opportunity for Zeta</th>
        <th style="padding:7px 10px;text-align:left;color:var(--txt3);font-weight:600;border-bottom:1px solid rgba(255,255,255,.08)">🔴 Risk / Challenge</th>
      </tr></thead>
      <tbody>
        <tr style="border-bottom:1px solid rgba(255,255,255,.05)">
          <td style="padding:7px 10px;font-weight:700;color:var(--txt1);white-space:nowrap">Market Concentration (HHI)</td>
          <td style="padding:7px 10px;color:var(--txt2)">How dominant the top players are. Calculated as sum of each company's squared market share × 10,000.</td>
          <td style="padding:7px 10px;color:#2fc97e">HHI &lt; 1000 — fragmented market, easier to win share</td>
          <td style="padding:7px 10px;color:#e05c5c">HHI &gt; 1800 — one player dominates, very hard to enter</td>
        </tr>
        <tr style="border-bottom:1px solid rgba(255,255,255,.05);background:rgba(255,255,255,.02)">
          <td style="padding:7px 10px;font-weight:700;color:var(--txt1);white-space:nowrap">CR4</td>
          <td style="padding:7px 10px;color:var(--txt2)">Combined share of the top 4 companies. Standard pharma competitive intensity benchmark.</td>
          <td style="padding:7px 10px;color:#2fc97e">CR4 &lt; 50% — market open, no clear cartel</td>
          <td style="padding:7px 10px;color:#e05c5c">CR4 &gt; 80% — top 4 locked in, minimal space for others</td>
        </tr>
        <tr style="border-bottom:1px solid rgba(255,255,255,.05)">
          <td style="padding:7px 10px;font-weight:700;color:var(--txt1);white-space:nowrap">Market Balance (Gini)</td>
          <td style="padding:7px 10px;color:var(--txt2)">Equality of share distribution across all players. 0.00 = everyone holds equal share. 1.00 = one company takes everything.</td>
          <td style="padding:7px 10px;color:#2fc97e">Gini &lt; 0.30 — balanced, fair competition among players</td>
          <td style="padding:7px 10px;color:#e05c5c">Gini &gt; 0.60 — severe imbalance, single player controls</td>
        </tr>
        <tr style="background:rgba(255,255,255,.02)">
          <td style="padding:7px 10px;font-weight:700;color:var(--txt1);white-space:nowrap">Strategic Position Matrix</td>
          <td style="padding:7px 10px;color:var(--txt2)">Plots Zeta's share against market concentration. Four quadrants guide resource decisions.</td>
          <td style="padding:7px 10px;color:var(--txt2)"><b style="color:#4c6ef5">🎯 GROW</b> (low HHI, low Zeta) — enter now &nbsp;|&nbsp; <b style="color:#2fc97e">🚀 ACCELERATE</b> (low HHI, high Zeta) — push harder</td>
          <td style="padding:7px 10px;color:var(--txt2)"><b style="color:#2fc97e">🛡 DEFEND</b> (high HHI, high Zeta) — protect lead &nbsp;|&nbsp; <b style="color:#e05c5c">⬇ DEPRIORITIZE</b> (high HHI, low Zeta) — costly to enter</td>
        </tr>
      </tbody>
    </table></div>
  </div>`;

  document.getElementById(SEC).innerHTML = aiInsightStrip(SEC) + pageHtml;

  // ── Chart 1: HHI horizontal bar ───────────────────────────────────────────
  const top15 = dm1HHI.slice(0,15);
  hBarChart('ch-conc-hhi',
    top15.map(x=>(LOOKUPS.dm1s[x.d]||'').substring(0,18)),
    top15.map(x=>x.hhi),
    top15.map(x=>x.hhi>1800?'rgba(224,92,92,.85)':x.hhi>1000?'rgba(255,159,69,.85)':'rgba(47,201,126,.85)'),
    {_pct:false, plugins:{annotation:{annotations:{
      line1:{type:'line',xMin:1000,xMax:1000,borderColor:'rgba(255,159,69,.6)',borderWidth:1,borderDash:[4,3]},
      line2:{type:'line',xMin:1800,xMax:1800,borderColor:'rgba(224,92,92,.6)',borderWidth:1,borderDash:[4,3]}
    }}}});

  // ── Chart 2: Strategic Position Matrix (Zeta Share vs HHI + quadrants) ──
  const totalAllMkt = dm1HHI.reduce((s,x)=>s+x.total,0)||1;
  destroyChart('ch-conc-scatter');
  const _sCtx = document.getElementById('ch-conc-scatter')?.getContext('2d');
  if(_sCtx){
    const _tc=v=>getComputedStyle(document.documentElement).getPropertyValue(v);
    // Quadrant dividers: HHI=1800 (vertical), Zeta share=15% (horizontal)
    const _hhiDiv=1800, _shareDiv=15;
    // Color by quadrant
    const _bubbleColor=x=>{
      const hi=x.hhi>_hhiDiv, hs=x.zetaShare*100>_shareDiv;
      if(!hi&&hs)  return 'rgba(47,201,126,.75)';   // low HHI + high share: ACCELERATE (green)
      if(hi&&hs)   return 'rgba(76,110,245,.75)';   // high HHI + high share: DEFEND (blue)
      if(!hi&&!hs) return 'rgba(255,184,0,.75)';    // low HHI + low share: GROW (amber)
      return 'rgba(224,92,92,.65)';                 // high HHI + low share: DEPRIORITIZE (red)
    };
    charts['ch-conc-scatter']=new Chart(_sCtx,{
      type:'bubble',
      data:{datasets:[{
        label:'Markets',
        data:dm1HHI.map(x=>({
          x:x.hhi, y:+(x.zetaShare*100).toFixed(2),
          r:Math.max(5,Math.min(22,Math.sqrt(x.total/totalAllMkt)*120)),
          name:(LOOKUPS.dm1s[x.d]||'').substring(0,20),
          struct:x.struct, domName:x.domName, zetaRank:x.zetaRank, gini:x.gini, cr4:x.cr4
        })),
        backgroundColor:dm1HHI.map(x=>_bubbleColor(x)),
        borderColor:dm1HHI.map(x=>_bubbleColor(x).replace(',.',',.').replace('.75','1').replace('.65','1').replace('.7','1')),
        borderWidth:1
      }]},
      options:{
        responsive:true,maintainAspectRatio:false,
        plugins:{
          legend:{display:false},
          tooltip:{callbacks:{label:ctx=>{
            const d=ctx.raw;
            const q=d.x>_hhiDiv?(d.y>_shareDiv?'🛡 DEFEND':'⬇ DEPRIORITIZE'):(d.y>_shareDiv?'🚀 ACCELERATE':'🎯 GROW');
            return [d.name,`HHI: ${d.x} (${d.struct})`,`Zeta Share: ${d.y}%`,
                    d.zetaRank?`Zeta Rank: #${d.zetaRank}`:'Zeta: not ranked',
                    `CR4: ${(d.cr4*100).toFixed(0)}%  |  Balance: ${d.gini.toFixed(2)}`,
                    `Dominant: ${d.domName}`,`Quadrant: ${q}`];
          }}},
          annotation:{annotations:{
            vLine:{type:'line',xMin:_hhiDiv,xMax:_hhiDiv,
              borderColor:'rgba(255,255,255,.25)',borderWidth:1,borderDash:[5,4]},
            hLine:{type:'line',yMin:_shareDiv,yMax:_shareDiv,
              borderColor:'rgba(255,255,255,.25)',borderWidth:1,borderDash:[5,4]},
            // Quadrant labels
            q1:{type:'label',xValue:500,yValue:_shareDiv*2.2,
              content:['🚀 ACCELERATE'],color:'rgba(47,201,126,.85)',
              font:{size:10,weight:'700'},textAlign:'center'},
            q2:{type:'label',xValue:_hhiDiv*1.18,yValue:_shareDiv*2.2,
              content:['🛡 DEFEND'],color:'rgba(76,110,245,.85)',
              font:{size:10,weight:'700'},textAlign:'center'},
            q3:{type:'label',xValue:500,yValue:_shareDiv*0.35,
              content:['🎯 GROW'],color:'rgba(255,184,0,.85)',
              font:{size:10,weight:'700'},textAlign:'center'},
            q4:{type:'label',xValue:_hhiDiv*1.18,yValue:_shareDiv*0.35,
              content:['⬇ DEPRIORITIZE'],color:'rgba(224,92,92,.85)',
              font:{size:10,weight:'700'},textAlign:'center'}
          }}
        },
        scales:{
          x:{title:{display:true,text:'Market Concentration (HHI)  ←  Competitive | Concentrated  →',color:_tc('--txt2'),font:{size:10}},
             ticks:{color:_tc('--txt3')},grid:{color:'rgba(255,255,255,.05)'}},
          y:{title:{display:true,text:'Zeta Market Share %',color:_tc('--txt2'),font:{size:10}},
             ticks:{color:_tc('--txt3'),callback:v=>v+'%'},grid:{color:'rgba(255,255,255,.05)'}}
        }
      }
    });
  }
  makeSortable('tbl-conc');
}
function renderForecast() {
  const SEC        = 's-forecast';
  const filterFn   = dimFilter();
  const rangeLabel = {mat:'MAT',ytd:'YTD',curr:'Month',all:'All','3m':'3M','6m':'6M'}[STATE.timeRange]||STATE.timeRange;
  const ml         = STATE.metric==='lcv'?'LCV':'SU';

  // ── Filter context ────────────────────────────────────────────────────────
  const _cp=[];
  if(STATE.fCorpSel.size>0)  _cp.push('Corp: '+[...STATE.fCorpSel].map(i=>(LOOKUPS.corps[i]||i)).join(', '));
  if(STATE.fDm1Sel.size>0)   _cp.push('Market: '+[...STATE.fDm1Sel].map(i=>(LOOKUPS.dm1s[i]||i)).join(', '));
  if(STATE.fBuSel.size>0)    _cp.push('BU: '+[...STATE.fBuSel].map(i=>(LOOKUPS.bus[i]||i)).join(', '));
  if(STATE.fLineSel.size>0)  _cp.push('Line: '+[...STATE.fLineSel].map(i=>(LOOKUPS.lines[i]||i)).join(', '));
  const ctxLabel = _cp.length>0?' · '+_cp.join(' | '):'';

  // ── Monthly series (all periods, filtered) ────────────────────────────────
  // Market denominator: ALL corps, but scoped to same therapeutic market (DM1/ATC4/DM2).
  // BU & Line filters are Zeta-internal concepts — competitors have no BU assignment,
  // so applying them to the market total would exclude all competitor rows and inflate share.
  const _mktFn = (c,p,t,a,d1,d2,ln,bu) => {
    if(STATE.fDm1Sel?.size  > 0 && !STATE.fDm1Sel.has(d1))  return false;
    if(STATE.fAtc4Sel?.size > 0 && !STATE.fAtc4Sel.has(a))  return false;
    if(STATE.fDm2Sel?.size  > 0 && !STATE.fDm2Sel.has(d2))  return false;
    return true;
  };
  // Zeta numerator: force Zeta corp + same market scope + BU/Line if active.
  const _zetaFn = (c,p,t,a,d1,d2,ln,bu) => {
    if(c !== ZETA_IDX) return false;
    if(STATE.fDm1Sel?.size  > 0 && !STATE.fDm1Sel.has(d1))  return false;
    if(STATE.fAtc4Sel?.size > 0 && !STATE.fAtc4Sel.has(a))  return false;
    if(STATE.fDm2Sel?.size  > 0 && !STATE.fDm2Sel.has(d2))  return false;
    if(STATE.fLineSel?.size > 0 && !STATE.fLineSel.has(ln)) return false;
    if(STATE.fBuSel?.size   > 0 && !STATE.fBuSel.has(bu))   return false;
    return true;
  };
  const totalByMonth = aggTotalByPeriod(_mktFn);
  const zetaByMonth  = aggTotalByPeriod(_zetaFn);

  // ── As Of cutoff: slice series at selected reference month ────────────────
  // This enables forecast vintaging — see what the model predicted at any point in time.
  const refIdx    = (STATE.fRefMonth != null && STATE.fRefMonth < NP) ? STATE.fRefMonth : NP - 1;
  const isLatest  = refIdx === NP - 1;
  const allMktV   = Array.from({length:NP},(_,i)=>MV(totalByMonth.get(i)||{lcv:0,su:0}));
  const allZetaV  = Array.from({length:NP},(_,i)=>MV(zetaByMonth.get(i)||{lcv:0,su:0}));
  const mktVals   = allMktV.slice(0, refIdx + 1);
  const zetaVals  = allZetaV.slice(0, refIdx + 1);

  // ── Helper: build forecast models from series ─────────────────────────────
  function buildModels(vals){
    const last12 = vals.slice(-12);
    const lastVal = vals[vals.length-1]||1;
    const val12Ago = vals[Math.max(0,vals.length-13)]||vals[0]||1;

    // 1. CAGR
    const monthlyCAGR = Math.pow(lastVal/(val12Ago||1),1/12)-1;
    const cagrFC = n => Math.round(lastVal*Math.pow(1+monthlyCAGR,n));

    // 2. 3-MA with trend
    const ma3arr = last12.map((_,i,a)=>{
      const s=Math.max(0,i-2); return a.slice(s,i+1).reduce((x,v)=>x+v,0)/(i-s+1);
    });
    const lastMA  = ma3arr[ma3arr.length-1];
    const maTrend = (ma3arr[ma3arr.length-1]-ma3arr[Math.max(0,ma3arr.length-4)])/3;
    const maFC    = n => Math.round(lastMA+maTrend*n);

    // 3. Linear Regression (OLS) on last 12 months
    const n12=last12.length, xMean=(n12-1)/2;
    const yMean=last12.reduce((s,v)=>s+v,0)/n12;
    const sxx=last12.reduce((s,_,i)=>s+(i-xMean)**2,0)||1;
    const sxy=last12.reduce((s,v,i)=>s+(i-xMean)*(v-yMean),0);
    const slope=sxy/sxx;
    const intercept=yMean-slope*xMean;
    const linFC  = n => Math.round(intercept+slope*(n12-1+n));

    // R² for linear model
    const ssTot=last12.reduce((s,v)=>s+(v-yMean)**2,0)||1;
    const ssRes=last12.reduce((s,v,i)=>s+(v-(intercept+slope*i))**2,0);
    const r2 = Math.max(0,1-ssRes/ssTot);

    // 4. Consensus = equal-weight average of 3 models
    const consFC = n => Math.round((cagrFC(n)+maFC(n)+linFC(n))/3);

    // Model agreement at 12M (% spread)
    const fc12 = [cagrFC(12),maFC(12),linFC(12)];
    const fc12Mean = fc12.reduce((s,v)=>s+v,0)/3;
    const fc12Spread = (Math.max(...fc12)-Math.min(...fc12))/(fc12Mean||1);

    return {cagrFC,maFC,linFC,consFC,monthlyCAGR,maTrend,slope,intercept,r2,fc12Spread,lastVal,lastMA,n12};
  }

  const mkt  = buildModels(mktVals);
  const zeta = buildModels(zetaVals);

  // ── Forecast period labels (next 12M from As Of cutoff) ──────────────────
  function nextPeriod(p,n){
    let y=parseInt(p.slice(0,4)),m=parseInt(p.slice(5,7));
    for(let i=0;i<n;i++){m++;if(m>12){m=1;y++;}}
    return y+'-'+(m<10?'0'+m:m);
  }
  const lastPeriod = LOOKUPS.periods[refIdx] || '';
  const fcLabels   = [1,3,6,9,12].map(n=>nextPeriod(lastPeriod,n));
  const asOfLabel  = isLatest ? '' : ` · <span style="color:var(--acc3);font-weight:700">As Of: ${lastPeriod}</span>`;

  // ── Implied share at 12M ──────────────────────────────────────────────────
  const mkt12   = mkt.consFC(12);
  const zeta12  = zeta.consFC(12);
  const share12 = mkt12>0 ? zeta12/mkt12 : 0;
  const curShare= mktVals[mktVals.length-1]>0 ? zetaVals[zetaVals.length-1]/mktVals[mktVals.length-1] : 0;

  // ── Model convergence signal ──────────────────────────────────────────────
  const converged = mkt.fc12Spread < 0.05;
  const diverged  = mkt.fc12Spread > 0.15;

  // ── Dynamic insights ──────────────────────────────────────────────────────
  const ins=[];
  const direction = mkt.monthlyCAGR>0.005?'growth':mkt.monthlyCAGR<-0.005?'contraction':'flat';
  ins.push(`<span style="color:${direction==='growth'?'#2fc97e':direction==='contraction'?'#e05c5c':'#ffb800'};font-weight:700">${direction==='growth'?'📈 Growth':'📉 Contraction / ➡ Flat'} trajectory</span> — Market monthly CAGR <b>${(mkt.monthlyCAGR*100).toFixed(2)}%</b>. Consensus 12M forecast: <b>${fmtLCV(mkt.consFC(12))}</b> ${ml}.`);
  if(converged)
    ins.push(`<span style="color:#2fc97e;font-weight:700">✅ High model confidence</span> — All three models agree within 5% spread`);
  if(diverged)
    ins.push(`<span style="color:#ff9f45;font-weight:700">⚠️ Model divergence</span> — Forecast models disagree by ${(mkt.fc12Spread*100).toFixed(0)}% spread. Use consensus with caution.`);
  const shareDelta = share12 - curShare;
  if(Math.abs(shareDelta) > 0.005) {
    const _scopeNote = (STATE.fBuSel?.size>0||STATE.fLineSel?.size>0)
      ? ` <span style="font-size:11px;color:var(--txt3)">(Zeta ${[...(STATE.fBuSel?.size>0?[...STATE.fBuSel].map(i=>LOOKUPS.bus?.[i]||i):[]),...(STATE.fLineSel?.size>0?[...STATE.fLineSel].map(i=>LOOKUPS.lines?.[i]||i):[])].join('/')} scope vs total market)</span>`
      : '';
    ins.push(`Zeta projected share in 12M: <b>${(share12*100).toFixed(1)}%</b> vs current <b>${(curShare*100).toFixed(1)}%</b>${_scopeNote} — <span style="color:${shareDelta>0?'#2fc97e':'#e05c5c'};font-weight:700">${shareDelta>0?'expanding':'contracting'}</span>.`);
  }
  if(Math.abs(zeta.monthlyCAGR - mkt.monthlyCAGR) > 0.005)
    ins.push(`Zeta growing <b>${zeta.monthlyCAGR>mkt.monthlyCAGR?'faster':'slower'}</b> than market (${(zeta.monthlyCAGR*100).toFixed(2)}% vs ${(mkt.monthlyCAGR*100).toFixed(2)}% monthly CAGR).`);

  // ── Build forecast table rows ─────────────────────────────────────────────
  const fcRows = fcLabels.map((lbl,i)=>{
    const n = [1,3,6,9,12][i];
    const mc = mkt.consFC(n), zc = zeta.consFC(n);
    const ms = mc>0?zc/mc:0;
    return `<tr>
      <td>${lbl}</td>
      <td>${fmtLCV(mkt.cagrFC(n))}</td><td>${fmtLCV(mkt.maFC(n))}</td><td>${fmtLCV(mkt.linFC(n))}</td>
      <td style="font-weight:700;color:var(--acc6)">${fmtLCV(mc)}</td>
      <td>${fmtLCV(zeta.consFC(n))}</td>
      <td style="font-weight:700;color:var(--acc2)">${(ms*100).toFixed(1)}%</td>
    </tr>`;
  }).join('');

  const insHtml = ins.length ? `<div class="ai-insight-strip">
    <div class="ais-header"><span class="ais-icon">🤖</span><span class="ais-title">AI Forecast Insights</span><span class="ais-ctx">${rangeLabel}${ctxLabel}</span></div>
    <ul class="ais-list">${ins.map(i=>`<li>${i}</li>`).join('')}</ul>
  </div>` : '';

  const pageHtml = `
  <div class="section-title">🔮 Forecasting Center${asOfLabel}</div>
  ${!isLatest ? `<div style="background:rgba(255,184,0,.1);border:1px solid rgba(255,184,0,.3);border-radius:8px;padding:10px 14px;margin-bottom:12px;font-size:13px;color:var(--acc3)">
    <b>📅 Forecast vintage: ${lastPeriod}</b> — Models trained on data up to this period. Projecting 12 months forward from ${lastPeriod}.
    ${!isLatest && allMktV.length - mktVals.length > 0 ? `<span style="color:var(--txt3);font-size:11px"> (${allMktV.length - mktVals.length} later months available but excluded from this vintage)</span>` : ''}
  </div>` : ''}
  ${insHtml}
  <div class="kpi-grid" style="margin-bottom:16px">
    <div class="kpi-card blue"><div class="kpi-label">Market 12M Consensus</div><div class="kpi-value">${fmtLCV(mkt.consFC(12))}</div><div class="kpi-sub">Forecast (${ml})</div></div>
    <div class="kpi-card green"><div class="kpi-label">Zeta 12M Consensus</div><div class="kpi-value">${fmtLCV(zeta.consFC(12))}</div><div class="kpi-sub">Forecast (${ml})</div></div>
    <div class="kpi-card purple"><div class="kpi-label">Projected Zeta Share</div><div class="kpi-value">${(share12*100).toFixed(1)}%</div><div class="kpi-sub">At 12M horizon</div></div>
    <div class="kpi-card orange"><div class="kpi-label">Market CAGR (Monthly)</div><div class="kpi-value">${(mkt.monthlyCAGR*100).toFixed(2)}%</div><div class="kpi-sub">Trailing 12M</div></div>
  </div>
  <div class="chart-box" style="margin-bottom:16px">
    <div class="chart-box-title">📊 Forecast Models — ${ml}</div>
    <div class="tbl-wrap"><table id="tbl-forecast" class="data-table">
      <thead><tr><th>Period</th><th>CAGR</th><th>3-MA</th><th>Linear</th><th>Consensus</th><th>Zeta (Cons.)</th><th>Share%</th></tr></thead>
      <tbody>${fcRows}</tbody>
    </table></div>
  </div>
  <div class="chart-box"><div class="chart-box-title">📈 Market vs Zeta Trend</div>
    <div class="chart-wrap" style="height:280px"><canvas id="ch-forecast-line"></canvas></div>
  </div>`;

  document.getElementById(SEC).innerHTML = pageHtml;

  const fcPeriods = fcLabels;
  // Historical window: last 12 months up to refIdx (As Of cutoff)
  const histStart = Math.max(0, refIdx - 11);
  const allLabels = [...LOOKUPS.periods.slice(histStart, refIdx + 1), ...fcPeriods];
  const histMkt   = mktVals.slice(-12);
  const histZeta  = zetaVals.slice(-12);
  const fcMkt12   = [1,3,6,9,12].map(n=>mkt.consFC(n));
  const fcZeta12  = [1,3,6,9,12].map(n=>zeta.consFC(n));

  lineChart('ch-forecast-line', allLabels, [
    {label:'Market (hist)',  data:[...histMkt,  null,null,null,null,null], color:'#4c6ef5'},
    {label:'Zeta (hist)',    data:[...histZeta, null,null,null,null,null], color:'#36c994'},
    {label:'Market (fc)',    data:[...Array(12).fill(null), ...fcMkt12],  color:'#4c6ef5', dashed:true},
    {label:'Zeta (fc)',      data:[...Array(12).fill(null), ...fcZeta12], color:'#36c994', dashed:true},
  ]);
}

// ══════════════════════════════════════════════════════════════════════════════
// TARGET ACHIEVEMENT
// ══════════════════════════════════════════════════════════════════════════════
function renderCorpLandscapeHTML(dm1TotMapExcl, corpDm1Map, metric, ml) {
  function gV(obj){return obj?(metric==='lcv'?obj.lcv:obj.su):0;}
  function fP(v){return v!=null?(v*100).toFixed(2)+'%':'—';}
  function fP1(v){return v!=null?(v*100).toFixed(1)+'%':'—';}

  // Build set of DM1 indices from TARGETS_2026, filtered by effective BU/Line (incl. BU Manager)
  var _effC=getEffectiveFilters();
  var hasBuFilt=_effC.hasBu, _buSelC=_effC.buSel;
  var hasLineFilt=_effC.hasLine, _lnSelC=_effC.lineSel;
  var tgtD1Set=new Set();
  TARGETS_2026.forEach(function(t){
    if(hasBuFilt){
      var buIdx=LOOKUPS.bus?LOOKUPS.bus.indexOf(t.bu||''):-1;
      if(buIdx<0||!_buSelC.has(buIdx)) return;
    }
    if(hasLineFilt){
      var lnIdx=LOOKUPS.lines?LOOKUPS.lines.indexOf(t.line||''):-1;
      if(lnIdx<0||!_lnSelC.has(lnIdx)) return;
    }
    var dm1Key=t.dm1.toUpperCase().trim();
    var idx=LOOKUPS.dm1s.findIndex(function(d){return d&&d.toUpperCase().trim()===dm1Key;});
    if(idx>=0) tgtD1Set.add(idx);
  });

  // Total market (excl Other Markets) across TARGETS_2026 DM1s
  var totalMkt=0;
  tgtD1Set.forEach(function(d1){
    var v=dm1TotMapExcl.get(d1);
    if(v) totalMkt+=gV(v);
  });

  // Zeta corp index
  var zetaIdx=LOOKUPS.corps.findIndex(function(c){return c&&c.toUpperCase().includes('ZETA PHARM');});

  // Per-corp blended share
  var corpList=[];
  corpDm1Map.forEach(function(d1Map,corpIdx){
    var corpTotal=0;
    tgtD1Set.forEach(function(d1){
      var v=d1Map.get(d1);
      if(v) corpTotal+=gV(v);
    });
    if(corpTotal<=0) return;
    var share=totalMkt>0?corpTotal/totalMkt:0;
    corpList.push({corpIdx:corpIdx,name:LOOKUPS.corps[corpIdx]||('Corp '+corpIdx),total:corpTotal,share:share,isZeta:corpIdx===zetaIdx});
  });
  corpList.sort(function(a,b){return b.share-a.share;});

  // Zeta rank
  var zetaRank=corpList.findIndex(function(c){return c.isZeta;})+1;
  var zetaEntry=corpList.find(function(c){return c.isZeta;});

  var h='';

  // Header KPIs
  h+='<div class="kpi-row" style="margin-bottom:24px">';
  h+='<div class="kpi-card"><div class="kpi-label">Total Corporations</div>'
    +'<div class="kpi-val" style="color:var(--acc1)">'+corpList.length+'</div>'
    +'<div class="kpi-sub">competing in defined markets</div></div>';
  h+='<div class="kpi-card"><div class="kpi-label">Total Market '+ml+'</div>'
    +'<div class="kpi-val" style="color:var(--txt1)">'+(totalMkt/1000000).toFixed(1)+'M</div>'
    +'<div class="kpi-sub">excl Other Markets BU</div></div>';
  h+='<div class="kpi-card" style="border-top:3px solid var(--acc1)"><div class="kpi-label">Zeta Rank</div>'
    +'<div class="kpi-val" style="color:var(--acc1)">#'+zetaRank+'</div>'
    +'<div class="kpi-sub">of '+corpList.length+' corporations</div></div>';
  h+='<div class="kpi-card" style="border-top:3px solid var(--acc1)"><div class="kpi-label">Zeta Blended Share</div>'
    +'<div class="kpi-val" style="color:var(--acc1)">'+(zetaEntry?fP1(zetaEntry.share):'—')+'</div>'
    +'<div class="kpi-sub">across all Zeta defined markets</div></div>';
  if(corpList.length>0){
    h+='<div class="kpi-card"><div class="kpi-label">Market Leader</div>'
      +'<div class="kpi-val" style="color:var(--txt1);font-size:14px">'+(corpList[0].name.replace('*','').trim())+'</div>'
      +'<div class="kpi-sub">'+fP1(corpList[0].share)+' blended share</div></div>';
  }
  h+='</div>';

  // Methodology note
  h+='<div style="padding:10px 14px;background:rgba(76,110,245,.08);border:1px solid rgba(76,110,245,.2);border-radius:8px;font-size:12px;color:var(--txt2);margin-bottom:20px">'
    +'<strong style="color:var(--acc1)">&#x1F4CA; Methodology:</strong> '
    +'Blended corporate share = corporation\'s total <strong>'+ml+'</strong> across all TARGETS_2026 DM1 markets &divide; combined total market size. '
    +'Rows tagged as <strong>Other Markets BU</strong> are excluded from both numerator and denominator. '
    +'Shows all '+corpList.length+' corporations active in Zeta\'s defined competitive markets.'
    +'</div>';

  // Bar chart scale
  var maxShare=corpList.length>0?corpList[0].share:0.01;

  // Table
  h+='<div style="overflow-x:auto">';
  h+='<table class="data-tbl" style="width:100%;border-collapse:collapse">';
  h+='<thead><tr>'
    +'<th style="text-align:center;width:40px">Rank</th>'
    +'<th>Corporation</th>'
    +'<th style="text-align:right">'+ml+' (K)</th>'
    +'<th style="text-align:right">Share %</th>'
    +'<th style="min-width:160px">Share Bar</th>'
    +'<th style="text-align:center">vs Zeta</th>'
    +'</tr></thead><tbody>';

  var showAll=corpList.length<=50;
  var displayList=showAll?corpList:corpList.slice(0,50);

  displayList.forEach(function(c,idx){
    var rank=idx+1;
    var barPct=maxShare>0?Math.min(100,c.share/maxShare*100):0;
    var zetaBarPct=zetaEntry&&maxShare>0?Math.min(100,zetaEntry.share/maxShare*100):0;
    var isAboveZeta=zetaEntry&&c.share>zetaEntry.share;
    var vsZeta=zetaEntry?(c.isZeta?'—':((c.share-zetaEntry.share)*100).toFixed(2)+' pp'):'-';
    var vsCol=c.isZeta?'var(--txt3)':(isAboveZeta?'var(--acc3)':'var(--acc2)');
    var rowBg=c.isZeta?'background:rgba(76,110,245,.08);font-weight:700;':'';
    var barCol=c.isZeta?'var(--acc1)':(isAboveZeta?'var(--acc3)':'rgba(93,103,140,.5)');
    h+='<tr style="border-left:3px solid '+(c.isZeta?'var(--acc1)':'transparent')+';'+rowBg+'">';
    h+='<td style="text-align:center;color:var(--txt2);font-size:12px">'+(c.isZeta?'<strong style="color:var(--acc1)">'+rank+'</strong>':rank)+'</td>';
    h+='<td>'+(c.isZeta?'<span style="color:var(--acc1)">&#11088; </span>':'')
      +c.name.replace('*','').trim()
      +(c.isZeta?' <span style="font-size:10px;background:rgba(76,110,245,.15);color:var(--acc1);padding:1px 5px;border-radius:4px">ZETA</span>':'')
      +'</td>';
    h+='<td style="text-align:right;color:var(--txt2)">'+(c.total/1000).toFixed(0)+'</td>';
    h+='<td style="text-align:right;font-weight:600;color:'+(c.isZeta?'var(--acc1)':'var(--txt1)')+'">'+fP(c.share)+'</td>';
    h+='<td style="padding:6px 8px">'
      +'<div style="position:relative;width:100%;height:10px;background:rgba(93,103,140,.15);border-radius:5px">'
      +'<div style="position:absolute;left:0;top:0;height:100%;width:'+barPct+'%;background:'+barCol+';border-radius:5px"></div>'
      +(zetaEntry&&!c.isZeta?'<div style="position:absolute;top:-2px;height:14px;width:2px;background:var(--acc1);left:'+zetaBarPct+'%" title="Zeta level"></div>':'')
      +'</div></td>';
    h+='<td style="text-align:center;font-size:12px;color:'+vsCol+'">'+(c.isZeta?'<span style="color:var(--txt3)">&#8212;</span>':(isAboveZeta?'+':'')+vsZeta)+'</td>';
    h+='</tr>';
  });

  if(!showAll){
    h+='<tr><td colspan="6" style="text-align:center;padding:12px;color:var(--txt3);font-size:12px">'
      +'Showing top 50 of '+corpList.length+' corporations &middot; '
      +'Zeta rank: #'+zetaRank
      +'</td></tr>';
  }

  h+='</tbody></table></div>';

  h+='<div style="margin-top:16px;padding:12px 16px;background:rgba(93,103,140,.08);border-radius:8px;font-size:12px;color:var(--txt2)">'
    +'<strong>Notes:</strong> Blended share uses same DM1 markets as TARGETS_2026 ('+tgtD1Set.size+' markets with flat data). '
    +'Other Markets BU excluded. Blue vertical line on bar = Zeta\'s share level. '
    +'Gap vs Zeta: positive = ahead of Zeta, negative = behind Zeta. '
    +'Metric: '+ml+' · MAT.'
    +'</div>';

  return h;
}

// ── Shared helper: build grouped stats for BU or Line, for either DM1 or DM2 ──
function buildGroupStats(groupKey, dmKey, totMapExcl, zetaDmMap, metric) {
  function gV(obj){return obj?(metric==='lcv'?obj.lcv:obj.su):0;}
  var isDm1=dmKey==='dm1';
  var tgtField=isDm1?'tgtDm1':'tgtDm2';
  var dmField=isDm1?'dm1':'dm2';
  var lookupArr=isDm1?LOOKUPS.dm1s:LOOKUPS.dm2s;
  var maFallback=MARKET_ACTUALS||{};

  // Effective BU/Line filters — respects BU Manager restriction even with no manual filter
  var _eff=getEffectiveFilters();
  var hasBuFilt=_eff.hasBu, _buSel=_eff.buSel;
  var hasLineFilt=_eff.hasLine, _lineSel=_eff.lineSel;

  // Group TARGETS_2026 by groupKey → unique DMs
  var groups={};
  TARGETS_2026.forEach(function(t){
    var gk=t[groupKey];
    if(!gk) return;
    // Filter: if BU filter active (incl. BU Manager restriction), only include matching BUs
    if(hasBuFilt){
      var buIdx=LOOKUPS.bus?LOOKUPS.bus.indexOf(t.bu||''):-1;
      if(buIdx<0||!_buSel.has(buIdx)) return;
    }
    // Filter: if Line filter active (incl. BU Manager restriction), only include matching Lines
    if(hasLineFilt){
      var lnIdx=LOOKUPS.lines?LOOKUPS.lines.indexOf(t.line||''):-1;
      if(lnIdx<0||!_lineSel.has(lnIdx)) return;
    }
    if(!groups[gk]) groups[gk]={dms:new Map()};
    var dmVal=t[dmField]||'';
    var dmKey2=dmVal.toUpperCase().trim();
    if(!groups[gk].dms.has(dmKey2)){
      var dIdx=lookupArr.findIndex(function(d){return d&&d.toUpperCase().trim()===dmKey2;});
      var isNew=dIdx<0, isPreComp=false;
      var mktVal=0,zetaVal=0,actual=null;
      if(!isNew){
        mktVal=gV(totMapExcl.get(dIdx));
        zetaVal=gV(zetaDmMap.get(dIdx));
        actual=mktVal>0?zetaVal/mktVal:0;
      } else {
        if(maFallback[dmKey2]!=null){actual=maFallback[dmKey2];isPreComp=true;}
      }
      groups[gk].dms.set(dmKey2,{dm:dmVal,dIdx:dIdx,isNew:isNew,isPreComp:isPreComp,actual:actual,zetaVal:zetaVal,mktVal:mktVal,tgts:[],prods:[]});
    }
    var entry=groups[gk].dms.get(dmKey2);
    if(t.prod&&entry.prods.indexOf(t.prod)<0) entry.prods.push(t.prod);
    if(t[tgtField]!=null) entry.tgts.push(t[tgtField]);
  });

  // Compute stats per group
  var statsList=[];
  function processGrp(gk){
    if(!groups[gk]) return;
    var sumZ=0,sumM=0,sumWtTgt=0,sumWtM=0;
    var detailRows=[];
    groups[gk].dms.forEach(function(e){
      var avgTgt=e.tgts.length?e.tgts.reduce(function(s,v){return s+v;},0)/e.tgts.length:null;
      if(!e.isNew&&!e.isPreComp){
        sumZ+=e.zetaVal; sumM+=e.mktVal;
        if(avgTgt!=null&&e.mktVal>0){sumWtTgt+=avgTgt*e.mktVal;sumWtM+=e.mktVal;}
      }
      detailRows.push({dm:e.dm,isNew:e.isNew,isPreComp:e.isPreComp,actual:e.actual,mktVal:e.mktVal,zetaVal:e.zetaVal,avgTgt:avgTgt,prods:e.prods});
    });
    detailRows.sort(function(a,b){return (b.mktVal||0)-(a.mktVal||0);});
    var blended=sumM>0?sumZ/sumM:null;
    var wtdTgt=sumWtM>0?sumWtTgt/sumWtM:null;
    var isApprox=false;
    if(blended===null){
      var pcs=detailRows.filter(function(r){return r.isPreComp&&r.actual!=null;});
      if(pcs.length>0){
        blended=pcs.reduce(function(s,r){return s+r.actual;},0)/pcs.length;
        var ptgts=pcs.filter(function(r){return r.avgTgt!=null;});
        if(ptgts.length>0) wtdTgt=ptgts.reduce(function(s,r){return s+r.avgTgt;},0)/ptgts.length;
        isApprox=true;
      }
    }
    var achieve=(blended!=null&&wtdTgt!=null&&wtdTgt>0)?blended/wtdTgt*100:null;
    var gap=(blended!=null&&wtdTgt!=null)?(blended-wtdTgt)*100:null;
    statsList.push({gk:gk,blended:blended,wtdTgt:wtdTgt,achieve:achieve,gap:gap,sumZ:sumZ,sumM:sumM,isApprox:isApprox,detailRows:detailRows});
  }

  // Default order for BU — exclude Other Markets and Non-Promoted
  var excludedGroups=['Other Markets','Non-Promoted','Non Promoted','NON-PROMOTED'];
  function isExcluded(gk){return excludedGroups.some(function(e){return gk.toUpperCase().trim()===e.toUpperCase();});}
  var defaultOrder=['CHC','Cluster','DIAB','GIT'];
  defaultOrder.forEach(processGrp);
  Object.keys(groups).forEach(function(gk){if(defaultOrder.indexOf(gk)<0&&!isExcluded(gk))processGrp(gk);});
  return statsList;
}

// ── Render a grouped achievement table (used by both BU and Line views) ──
function renderGroupedAchHTML(statsList, groupLabel, dmLabel, ml) {
  function ragC(a){if(a==null)return '#9da8c5';if(a>=100)return 'var(--acc2)';if(a>=80)return '#f59e0b';return 'var(--acc3)';}
  function ragI(a){if(a==null)return '&#9898;';if(a>=100)return '&#128994;';if(a>=80)return '&#128993;';return '&#128308;';}
  function fP(v){return v!=null?(v*100).toFixed(1)+'%':'&#8212;';}
  var h='';
  // Summary cards
  h+='<div class="kpi-row" style="margin-bottom:20px">';
  statsList.forEach(function(s){
    var col=ragC(s.achieve);
    h+='<div class="kpi-card" style="border-top:3px solid '+col+'">'
      +'<div class="kpi-label">'+s.gk+'</div>'
      +'<div class="kpi-val" style="color:'+col+'">'+(s.isApprox?'&#8776; ':'')+fP(s.blended)+'</div>'
      +'<div class="kpi-sub">'+ragI(s.achieve)+' '+(s.achieve!=null?s.achieve.toFixed(0)+'% of tgt':(s.blended!=null?'est.':'&#8212;'))+'</div>'
      +'<div style="font-size:11px;color:var(--txt3);margin-top:2px">Tgt: '+(s.wtdTgt!=null?fP(s.wtdTgt):'TBD')+(s.gap!=null?' &middot; '+(s.gap>=0?'+':'')+s.gap.toFixed(1)+'pp':'')+'</div>'
      +'</div>';
  });
  h+='</div>';
  // Detail tables
  statsList.forEach(function(s){
    var col=ragC(s.achieve);
    h+='<div style="margin-bottom:24px">';
    h+='<div style="background:rgba(93,103,140,.12);border-left:4px solid '+col+';padding:9px 14px;border-radius:6px;margin-bottom:8px;display:flex;align-items:center;gap:14px;flex-wrap:wrap">'
      +'<span style="font-weight:700;color:var(--acc1);font-size:13px;text-transform:uppercase;letter-spacing:.04em">'+s.gk+'</span>'
      +'<span style="font-size:14px;font-weight:700;color:'+col+'">'+(s.isApprox?'&#8776; ':'')+fP(s.blended)+'</span>'
      +'<span style="font-size:12px;color:var(--txt2)">vs target '+fP(s.wtdTgt)+'</span>'
      +(s.achieve!=null?'<span style="font-size:12px;font-weight:600;color:'+col+'">'+ragI(s.achieve)+' '+s.achieve.toFixed(0)+'% achieved</span>':'')
      +(s.gap!=null?'<span style="font-size:12px;color:'+col+';font-weight:600">'+(s.gap>=0?'+':'')+s.gap.toFixed(1)+' pp gap</span>':'')
      +'</div>';
    h+='<table class="data-tbl" style="width:100%;border-collapse:collapse;font-size:12px"><thead><tr>'
      +'<th>Market ('+dmLabel+')</th><th>Products</th>'
      +'<th style="text-align:right">Mkt '+ml+' (K)</th>'
      +'<th style="text-align:right">Zeta '+ml+' (K)</th>'
      +'<th style="text-align:center">Actual%</th>'
      +'<th style="text-align:center">Target%</th>'
      +'<th style="text-align:center">Achievement</th>'
      +'<th style="text-align:center">Gap (pp)</th>'
      +'</tr></thead><tbody>';
    s.detailRows.forEach(function(r){
      var ach2=r.actual!=null&&r.avgTgt!=null&&r.avgTgt>0?r.actual/r.avgTgt*100:null;
      var gap2=r.actual!=null&&r.avgTgt!=null?(r.actual-r.avgTgt)*100:null;
      var lc=ragC(ach2);
      h+='<tr style="border-left:3px solid '+lc+'">';
      h+='<td style="max-width:170px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="'+r.dm+'">'
        +r.dm.substring(0,30)+(r.dm.length>30?'&#8230;':'')
        +(r.isPreComp?' <span style="font-size:10px;background:rgba(16,185,129,.15);color:#10b981;padding:1px 4px;border-radius:3px">&#8776;</span>':'')
        +(r.isNew&&!r.isPreComp?' <span style="font-size:10px;background:rgba(76,110,245,.15);color:var(--acc1);padding:1px 4px;border-radius:3px">NEW</span>':'')
        +'</td>';
      h+='<td style="color:var(--txt2);font-size:11px;max-width:110px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="'+r.prods.join(', ')+'">'+r.prods.join(', ')+'</td>';
      h+='<td style="text-align:right;color:var(--txt2)">'+(r.mktVal>0?(r.mktVal/1000).toFixed(0):'&#8212;')+'</td>';
      h+='<td style="text-align:right;color:var(--txt2)">'+(r.mktVal>0?(r.zetaVal/1000).toFixed(0):'&#8212;')+'</td>';
      h+='<td style="text-align:center;font-weight:600">'+fP(r.actual)+'</td>';
      h+='<td style="text-align:center">'+fP(r.avgTgt)+'</td>';
      h+='<td style="text-align:center">'+(ach2!=null?'<span style="background:'+lc+'22;color:'+lc+';padding:2px 7px;border-radius:10px;border:1px solid '+lc+'44;font-size:11px">'+ragI(ach2)+' '+ach2.toFixed(0)+'%</span>':'<span style="color:var(--txt3)">&#8212;</span>')+'</td>';
      var gcol=gap2!=null?(gap2>=0?'var(--acc2)':'var(--acc3)'):'var(--txt3)';
      h+='<td style="text-align:center;color:'+gcol+';font-weight:600">'+(gap2!=null?(gap2>=0?'+':'')+gap2.toFixed(1)+' pp':'&#8212;')+'</td>';
      h+='</tr>';
    });
    h+='</tbody></table></div>';
  });
  return h;
}

function renderBuSummaryHTML(dm1TotMapExcl, zetaDm1Map, dm2TotMapExcl, zetaDm2Map, metric, ml) {
  var h='';
  // Methodology note
  h+='<div style="padding:9px 14px;background:rgba(76,110,245,.08);border:1px solid rgba(76,110,245,.2);border-radius:8px;font-size:12px;color:var(--txt2);margin-bottom:16px">'
    +'<strong style="color:var(--acc1)">&#x1F4CA; Methodology:</strong> '
    +'Blended Share = &#x3A3; Zeta <strong>'+ml+'</strong> across all BU markets &divide; &#x3A3; total market sizes (each unique market counted once, Other Markets BU excluded). '
    +'Weighted Target = &#x3A3;(avg product target &times; market size) &divide; &#x3A3; market sizes. '
    +'<span style="color:#10b981">&#8776;</span> = pre-computed from MARKET_ACTUALS.'
    +'</div>';
  // DM1/DM2 sub-tabs
  var uid='bus'+Date.now();
  h+='<div style="display:flex;gap:0;margin-bottom:16px;border-bottom:1px solid var(--bdr)">'
    +'<button id="'+uid+'-dm1" onclick="taSubTab(\''+uid+'\',\'dm1\')" style="padding:6px 16px;border:none;border-bottom:2px solid var(--acc2);margin-bottom:-1px;background:transparent;color:var(--acc2);font-weight:600;cursor:pointer;font-size:12px">Defined Market 1</button>'
    +'<button id="'+uid+'-dm2" onclick="taSubTab(\''+uid+'\',\'dm2\')" style="padding:6px 16px;border:none;border-bottom:2px solid transparent;margin-bottom:-1px;background:transparent;color:var(--txt2);font-weight:400;cursor:pointer;font-size:12px">Defined Market 2</button>'
    +'</div>';
  var dm1Stats=buildGroupStats('bu','dm1',dm1TotMapExcl,zetaDm1Map,metric);
  var dm2Stats=buildGroupStats('bu','dm2',dm2TotMapExcl,zetaDm2Map,metric);
  h+='<div id="'+uid+'-dm1-content">'+renderGroupedAchHTML(dm1Stats,'bu','DM1',ml)+'</div>';
  h+='<div id="'+uid+'-dm2-content" style="display:none">'+renderGroupedAchHTML(dm2Stats,'bu','DM2',ml)+'</div>';
  h+='<div style="padding:10px 14px;background:rgba(93,103,140,.08);border-radius:8px;font-size:12px;color:var(--txt2);margin-top:4px">'
    +'<strong>Notes:</strong> Each market counted once per BU. Avg Target = simple average of product-level targets for that market. '
    +'Markets with &#8776; excluded from blended sum (pre-computed share only).'
    +'</div>';
  return h;
}

