function renderZetaTotalHTML(dm1TotMapExcl, zetaDm1Map, dm2TotMapExcl, zetaDm2Map, metric, ml) {
  function gV(obj){return obj?(metric==='lcv'?obj.lcv:obj.su):0;}
  function ragC(a){if(a==null)return '#9da8c5';if(a>=100)return 'var(--acc2)';if(a>=80)return '#f59e0b';return 'var(--acc3)';}
  function ragI(a){if(a==null)return '&#9898;';if(a>=100)return '&#128994;';if(a>=80)return '&#128993;';return '&#128308;';}
  function fP(v){return v!=null?(v*100).toFixed(1)+'%':'&#8212;';}

  var EXCL_BUS=['other market','non-promoted','non promoted','non_promoted'];
  function isBuExcl(bn){return bn&&EXCL_BUS.some(function(e){return bn.toLowerCase().includes(e);});}

  // Effective BU filter for Zeta Total view (BU Manager sees only their BUs)
  var _effZ=getEffectiveFilters();
  var _ztHasBu=_effZ.hasBu, _ztBuSel=_effZ.buSel;

  // Build Zeta total + per-BU stats for a given DM dimension
  function computeZetaDm(dmKey, totMapExcl, zetaDmMap) {
    var isDm1=dmKey==='dm1';
    var tgtField=isDm1?'tgtDm1':'tgtDm2';
    var dmField=isDm1?'dm1':'dm2';
    var lookupArr=isDm1?LOOKUPS.dm1s:LOOKUPS.dm2s;
    var maFallback=MARKET_ACTUALS||{};

    // All unique markets across all non-excluded BUs (counted ONCE for total)
    var totalDmMap=new Map(); // dmKey2 → {dm,dIdx,isPreComp,actual,zetaVal,mktVal,tgts[]}
    // Per-BU breakdown
    var buDmMap={};          // buName → Map(dmKey2 → same shape)

    TARGETS_2026.forEach(function(t){
      if(isBuExcl(t.bu||'')) return;
      // BU Manager gate: skip BUs not in their allowed set
      if(_ztHasBu){
        var _buIdx2=LOOKUPS.bus?LOOKUPS.bus.indexOf(t.bu||''):-1;
        if(_buIdx2<0||!_ztBuSel.has(_buIdx2)) return;
      }
      var buName=t.bu||'(none)';
      var dmVal=t[dmField]||'';
      var dmKey2=dmVal.toUpperCase().trim();
      var dIdx=lookupArr.findIndex(function(d){return d&&d.toUpperCase().trim()===dmKey2;});
      var isNew=dIdx<0, isPreComp=false;
      var mktVal=0, zetaVal=0, actual=null;
      if(!isNew){
        mktVal=gV(totMapExcl.get(dIdx));
        zetaVal=gV(zetaDmMap.get(dIdx));
        actual=mktVal>0?zetaVal/mktVal:0;
      } else {
        if(maFallback[dmKey2]!=null){actual=maFallback[dmKey2];isPreComp=true;}
      }
      // Total map (market counted once across all BUs)
      if(!totalDmMap.has(dmKey2)) totalDmMap.set(dmKey2,{dm:dmVal,dIdx:dIdx,isNew:isNew,isPreComp:isPreComp,actual:actual,zetaVal:zetaVal,mktVal:mktVal,tgts:[]});
      var te=totalDmMap.get(dmKey2);
      if(t[tgtField]!=null) te.tgts.push(t[tgtField]);
      // BU map
      if(!buDmMap[buName]) buDmMap[buName]=new Map();
      if(!buDmMap[buName].has(dmKey2)) buDmMap[buName].set(dmKey2,{dm:dmVal,dIdx:dIdx,isNew:isNew,isPreComp:isPreComp,actual:actual,zetaVal:zetaVal,mktVal:mktVal,tgts:[]});
      var be=buDmMap[buName].get(dmKey2);
      if(t[tgtField]!=null) be.tgts.push(t[tgtField]);
    });

    // Aggregate helper
    function agg(dmMapEntries){
      var sumZ=0,sumM=0,sumWtTgt=0,sumWtM=0,isApprox=false,precompSum=0,precompN=0,precompTgtSum=0,precompTgtN=0;
      dmMapEntries.forEach(function(e){
        var avgTgt=e.tgts.length?e.tgts.reduce(function(s,v){return s+v;},0)/e.tgts.length:null;
        if(!e.isNew&&!e.isPreComp){
          sumZ+=e.zetaVal; sumM+=e.mktVal;
          if(avgTgt!=null&&e.mktVal>0){sumWtTgt+=avgTgt*e.mktVal;sumWtM+=e.mktVal;}
        } else if(e.isPreComp&&e.actual!=null){
          precompSum+=e.actual; precompN++;
          if(avgTgt!=null){precompTgtSum+=avgTgt;precompTgtN++;}
        }
      });
      var blended=sumM>0?sumZ/sumM:null;
      var wtdTgt=sumWtM>0?sumWtTgt/sumWtM:null;
      if(blended===null&&precompN>0){blended=precompSum/precompN;isApprox=true;if(precompTgtN>0)wtdTgt=precompTgtSum/precompTgtN;}
      var achieve=(blended!=null&&wtdTgt!=null&&wtdTgt>0)?blended/wtdTgt*100:null;
      var gap=(blended!=null&&wtdTgt!=null)?(blended-wtdTgt)*100:null;
      return{blended:blended,wtdTgt:wtdTgt,achieve:achieve,gap:gap,sumZ:sumZ,sumM:sumM,isApprox:isApprox};
    }

    // Zeta total
    var totalStats=agg(Array.from(totalDmMap.values()));

    // Per-BU stats in fixed order
    var buOrder=['CHC','Cluster','DIAB','GIT'];
    var buRows=[];
    buOrder.forEach(function(bn){
      if(!buDmMap[bn]) return;
      var s=agg(Array.from(buDmMap[bn].values()));
      s.bu=bn;
      buRows.push(s);
    });
    // Any extra BUs not in default order
    Object.keys(buDmMap).forEach(function(bn){
      if(buOrder.indexOf(bn)<0&&!isBuExcl(bn)){
        var s=agg(Array.from(buDmMap[bn].values())); s.bu=bn; buRows.push(s);
      }
    });

    return{total:totalStats, buRows:buRows};
  }

  function renderDmPanel(dmKey, totMapExcl, zetaDmMap, dmLabel){
    var res=computeZetaDm(dmKey, totMapExcl, zetaDmMap);
    var tot=res.total; var buRows=res.buRows;
    var col=ragC(tot.achieve);
    var h='';

    // Hero card
    h+='<div style="background:linear-gradient(135deg,rgba(76,110,245,.13),rgba(76,110,245,.04));border:1px solid rgba(76,110,245,.3);border-left:5px solid '+col+';border-radius:10px;padding:20px 24px;margin-bottom:20px;display:flex;align-items:center;gap:20px;flex-wrap:wrap">'
      +'<div style="flex:1;min-width:180px">'
      +'<div style="font-size:11px;font-weight:700;color:var(--acc1);letter-spacing:.08em;text-transform:uppercase;margin-bottom:6px">ZETA PHARMA &mdash; TOTAL PORTFOLIO &bull; '+dmLabel+'</div>'
      +'<div style="font-size:34px;font-weight:800;color:'+col+';line-height:1">'+(tot.isApprox?'&#8776; ':'')+fP(tot.blended)+'</div>'
      +'<div style="font-size:13px;color:var(--txt2);margin-top:6px">Blended Market Share &nbsp;&bull;&nbsp; Target: <strong>'+fP(tot.wtdTgt)+'</strong></div>'
      +'</div>'
      +'<div style="text-align:center;min-width:130px">'
      +'<div style="font-size:30px;font-weight:800;color:'+col+'">'+ragI(tot.achieve)+' '+(tot.achieve!=null?tot.achieve.toFixed(0)+'%':'&mdash;')+'</div>'
      +'<div style="font-size:12px;color:var(--txt2);margin-top:2px">Achievement</div>'
      +'<div style="font-size:13px;color:'+col+';font-weight:600;margin-top:4px">'+(tot.gap!=null?(tot.gap>=0?'+':'')+tot.gap.toFixed(1)+' pp':'')+'</div>'
      +'</div>'
      +'</div>';

    // BU breakdown table
    h+='<div style="font-size:11px;font-weight:700;color:var(--txt3);letter-spacing:.06em;text-transform:uppercase;margin-bottom:8px">Breakdown by Business Unit</div>';
    h+='<table class="data-tbl" style="width:100%;border-collapse:collapse;font-size:13px"><thead><tr>'
      +'<th style="width:130px">Business Unit</th>'
      +'<th style="text-align:right">Market '+ml+' (K)</th>'
      +'<th style="text-align:right">Zeta '+ml+' (K)</th>'
      +'<th style="text-align:center">Actual %</th>'
      +'<th style="text-align:center">Target %</th>'
      +'<th style="text-align:center">Achievement</th>'
      +'<th style="text-align:center">Gap (pp)</th>'
      +'</tr></thead><tbody>';

    buRows.forEach(function(s){
      var c2=ragC(s.achieve);
      h+='<tr style="border-left:4px solid '+c2+'">'
        +'<td style="font-weight:700;color:var(--acc1)">'+s.bu+(s.isApprox?' <span style="font-size:10px;color:#10b981">&#8776;</span>':'')+'</td>'
        +'<td style="text-align:right;color:var(--txt2)">'+(s.sumM>0?(s.sumM/1000).toFixed(0):'&mdash;')+'</td>'
        +'<td style="text-align:right;color:var(--txt2)">'+(s.sumZ>0?(s.sumZ/1000).toFixed(0):'&mdash;')+'</td>'
        +'<td style="text-align:center;font-weight:600;color:'+c2+'">'+(s.isApprox?'&#8776; ':'')+fP(s.blended)+'</td>'
        +'<td style="text-align:center">'+fP(s.wtdTgt)+'</td>'
        +'<td style="text-align:center">'+(s.achieve!=null?'<span style="background:'+c2+'22;color:'+c2+';padding:2px 9px;border-radius:10px;border:1px solid '+c2+'44;font-size:12px">'+ragI(s.achieve)+' '+s.achieve.toFixed(0)+'%</span>':'<span style="color:var(--txt3)">&mdash;</span>')+'</td>';
      var gc=s.gap!=null?(s.gap>=0?'var(--acc2)':'var(--acc3)'):'var(--txt3)';
      h+='<td style="text-align:center;color:'+gc+';font-weight:600">'+(s.gap!=null?(s.gap>=0?'+':'')+s.gap.toFixed(1)+' pp':'&mdash;')+'</td></tr>';
    });

    // Total row
    var tc=ragC(tot.achieve);
    h+='<tr style="border-top:2px solid var(--bdr);border-left:4px solid '+tc+';font-weight:700;background:rgba(76,110,245,.07)">'
      +'<td style="color:var(--acc1)">ZETA TOTAL</td>'
      +'<td style="text-align:right">'+(tot.sumM>0?(tot.sumM/1000).toFixed(0):'&mdash;')+'</td>'
      +'<td style="text-align:right">'+(tot.sumZ>0?(tot.sumZ/1000).toFixed(0):'&mdash;')+'</td>'
      +'<td style="text-align:center;color:'+tc+'">'+(tot.isApprox?'&#8776; ':'')+fP(tot.blended)+'</td>'
      +'<td style="text-align:center">'+fP(tot.wtdTgt)+'</td>'
      +'<td style="text-align:center"><span style="background:'+tc+'22;color:'+tc+';padding:2px 9px;border-radius:10px;border:1px solid '+tc+'44;font-size:12px">'+ragI(tot.achieve)+' '+(tot.achieve!=null?tot.achieve.toFixed(0)+'%':'&mdash;')+'</span></td>';
    var tgc=tot.gap!=null?(tot.gap>=0?'var(--acc2)':'var(--acc3)'):'var(--txt3)';
    h+='<td style="text-align:center;color:'+tgc+';font-weight:600">'+(tot.gap!=null?(tot.gap>=0?'+':'')+tot.gap.toFixed(1)+' pp':'&mdash;')+'</td></tr>';
    h+='</tbody></table>';
    return h;
  }

  var h='';
  h+='<div style="padding:9px 14px;background:rgba(76,110,245,.08);border:1px solid rgba(76,110,245,.2);border-radius:8px;font-size:12px;color:var(--txt2);margin-bottom:16px">'
    +'<strong style="color:var(--acc1)">&#127919; Methodology:</strong> '
    +'Zeta Total Blended Share = &Sigma; Zeta <strong>'+ml+'</strong> across ALL defined markets &divide; &Sigma; market sizes (each market counted ONCE, excl. Other Markets &amp; Non-Promoted). '
    +'BU rows reflect each BU&rsquo;s standalone blended share. '
    +'Note: BU market totals may not sum to Zeta Total if markets span multiple BUs.'
    +'</div>';

  var uid='zet'+Date.now();
  h+='<div style="display:flex;gap:0;margin-bottom:16px;border-bottom:1px solid var(--bdr)">'
    +'<button id="'+uid+'-dm1" onclick="taSubTab(\''+uid+'\',\'dm1\')" style="padding:6px 16px;border:none;border-bottom:2px solid var(--acc2);margin-bottom:-1px;background:transparent;color:var(--acc2);font-weight:600;cursor:pointer;font-size:12px">Defined Market 1</button>'
    +'<button id="'+uid+'-dm2" onclick="taSubTab(\''+uid+'\',\'dm2\')" style="padding:6px 16px;border:none;border-bottom:2px solid transparent;margin-bottom:-1px;background:transparent;color:var(--txt2);font-weight:400;cursor:pointer;font-size:12px">Defined Market 2</button>'
    +'</div>';
  h+='<div id="'+uid+'-dm1-content">'+renderDmPanel('dm1',dm1TotMapExcl,zetaDm1Map,'DM1')+'</div>';
  h+='<div id="'+uid+'-dm2-content" style="display:none">'+renderDmPanel('dm2',dm2TotMapExcl,zetaDm2Map,'DM2')+'</div>';
  h+='<div style="padding:10px 14px;background:rgba(93,103,140,.08);border-radius:8px;font-size:12px;color:var(--txt2);margin-top:12px">'
    +'<strong>Note:</strong> Each market is counted once in Zeta Total — markets shared across BUs are not double-counted. '
    +'BU row sums &#8800; Zeta Total by design.'
    +'</div>';
  return h;
}

function renderBuSummaryHTML_OLD(dm1TotMap, zetaDm1Map, metric, ml) {
  function gV(obj){return obj?(metric==='lcv'?obj.lcv:obj.su):0;}
  function ragC(a){if(a==null)return '#9da8c5';if(a>=100)return 'var(--acc2)';if(a>=80)return '#f59e0b';return 'var(--acc3)';}
  function ragI(a){if(a==null)return '&#9898;';if(a>=100)return '&#128994;';if(a>=80)return '&#128993;';return '&#128308;';}
  function fP(v){return v!=null?(v*100).toFixed(1)+'%':'&#8212;';}

  // Group TARGETS_2026 by BU → unique DM1s (each DM1 counted once per BU)
  var buGroups={};
  TARGETS_2026.forEach(function(t){
    if(!buGroups[t.bu]) buGroups[t.bu]={dm1s:new Map()};
    var dm1Key=t.dm1.toUpperCase().trim();
    if(!buGroups[t.bu].dm1s.has(dm1Key)){
      var d1Idx=LOOKUPS.dm1s.findIndex(function(d){return d&&d.toUpperCase().trim()===dm1Key;});
      var isNew=d1Idx<0, isPreComp=false;
      var mktVal=0, zetaVal=0, actual=null;
      if(!isNew){
        mktVal=gV(dm1TotMap.get(d1Idx));
        zetaVal=gV(zetaDm1Map.get(d1Idx));
        actual=mktVal>0?zetaVal/mktVal:0;
      } else {
        if(MARKET_ACTUALS[dm1Key]!=null){actual=MARKET_ACTUALS[dm1Key];isPreComp=true;}
      }
      buGroups[t.bu].dm1s.set(dm1Key,{dm1:t.dm1,d1Idx:d1Idx,isNew:isNew,isPreComp:isPreComp,actual:actual,zetaVal:zetaVal,mktVal:mktVal,tgts:[],prods:[]});
    }
    var entry=buGroups[t.bu].dm1s.get(dm1Key);
    if(t.prod&&entry.prods.indexOf(t.prod)<0) entry.prods.push(t.prod);
    if(t.tgtDm1!=null) entry.tgts.push(t.tgtDm1);
  });

  var buOrder=['CHC','Cluster','DIAB','GIT'];
  var buStats=[];

  function processGrp(bu){
    if(!buGroups[bu]) return;
    var sumZ=0, sumM=0, sumWtTgt=0, sumWtM=0;
    var detailRows=[];
    buGroups[bu].dm1s.forEach(function(e){
      var avgTgt=e.tgts.length?e.tgts.reduce(function(s,v){return s+v;},0)/e.tgts.length:null;
      if(!e.isNew&&!e.isPreComp){
        sumZ+=e.zetaVal; sumM+=e.mktVal;
        if(avgTgt!=null&&e.mktVal>0){sumWtTgt+=avgTgt*e.mktVal;sumWtM+=e.mktVal;}
      }
      detailRows.push({dm1:e.dm1,isNew:e.isNew,isPreComp:e.isPreComp,actual:e.actual,mktVal:e.mktVal,zetaVal:e.zetaVal,avgTgt:avgTgt,prods:e.prods});
    });
    detailRows.sort(function(a,b){return (b.mktVal||0)-(a.mktVal||0);});
    var blended=sumM>0?sumZ/sumM:null;
    var wtdTgt=sumWtM>0?sumWtTgt/sumWtM:null;
    var isApprox=false;
    // Fallback: if no flat-data markets, use equal-weighted average of pre-computed actuals
    if(blended===null){
      var pcs=detailRows.filter(function(r){return r.isPreComp&&r.actual!=null;});
      if(pcs.length>0){
        blended=pcs.reduce(function(s,r){return s+r.actual;},0)/pcs.length;
        var ptgts=pcs.filter(function(r){return r.avgTgt!=null;});
        if(ptgts.length>0) wtdTgt=ptgts.reduce(function(s,r){return s+r.avgTgt;},0)/ptgts.length;
        isApprox=true;
      }
    }
    var achieve=(blended!=null&&wtdTgt!=null&&wtdTgt>0)?blended/wtdTgt*100:null;
    var gap=(blended!=null&&wtdTgt!=null)?(blended-wtdTgt)*100:null;
    buStats.push({bu:bu,blended:blended,wtdTgt:wtdTgt,achieve:achieve,gap:gap,sumZ:sumZ,sumM:sumM,isApprox:isApprox,detailRows:detailRows});
  }
  buOrder.forEach(processGrp);
  Object.keys(buGroups).forEach(function(bu){if(buOrder.indexOf(bu)<0)processGrp(bu);});

  var h='';

  // BU summary cards
  h+='<div class="kpi-row" style="margin-bottom:24px">';
  buStats.forEach(function(s){
    var col=ragC(s.achieve);
    h+='<div class="kpi-card" style="border-top:3px solid '+col+'">'
      +'<div class="kpi-label">'+s.bu+'</div>'
      +'<div class="kpi-val" style="color:'+col+'">'+(s.isApprox?'<span style="font-size:14px">&#8776;</span> ':'')+fP(s.blended)+'</div>'
      +'<div class="kpi-sub">'+ragI(s.achieve)+' '+(s.achieve!=null?s.achieve.toFixed(0)+'% of target':(s.blended!=null?'est. blended':'no data'))+'</div>'
      +'<div style="font-size:11px;color:var(--txt3);margin-top:4px">Tgt: '+(s.wtdTgt!=null?fP(s.wtdTgt):'TBD')+(s.gap!=null?' &middot; '+(s.gap>=0?'+':'')+s.gap.toFixed(1)+'pp gap':'')+'</div>'
      +'</div>';
  });
  h+='</div>';

  // Methodology callout
  h+='<div style="padding:10px 14px;background:rgba(76,110,245,.08);border:1px solid rgba(76,110,245,.2);border-radius:8px;font-size:12px;color:var(--txt2);margin-bottom:20px">'
    +'<strong style="color:var(--acc1)">&#x1F4CA; Methodology:</strong> '
    +'BU Blended Share = &#x3A3; Zeta <strong>'+ml+'</strong> across all BU markets &divide; &#x3A3; total market sizes (each unique DM1 counted once). '
    +'Weighted Target = &#x3A3;(avg product target &times; market size) &divide; &#x3A3; market sizes. '
    +'<span style="color:#10b981">&#8776;</span> = pre-computed share from MARKET_ACTUALS (no raw data).'
    +'</div>';

  // Detail breakdown per BU
  buStats.forEach(function(s){
    var col=ragC(s.achieve);
    h+='<div style="margin-bottom:28px">';
    h+='<div style="background:rgba(93,103,140,.12);border-left:4px solid '+col+';padding:10px 16px;border-radius:6px;margin-bottom:8px;display:flex;align-items:center;gap:16px;flex-wrap:wrap">'
      +'<span style="font-weight:700;color:var(--acc1);font-size:13px;text-transform:uppercase;letter-spacing:.05em">'+s.bu+'</span>'
      +'<span style="font-size:14px;font-weight:700;color:'+col+'">'+(s.isApprox?'&#8776; ':'')+fP(s.blended)+'</span>'
      +'<span style="font-size:12px;color:var(--txt2)">vs target '+fP(s.wtdTgt)+'</span>'
      +(s.achieve!=null?'<span style="font-size:12px;font-weight:600;color:'+col+'">'+ragI(s.achieve)+' '+s.achieve.toFixed(0)+'% achieved</span>':'')
      +(s.gap!=null?'<span style="font-size:12px;color:'+col+';font-weight:600">'+(s.gap>=0?'+':'')+s.gap.toFixed(1)+' pp gap</span>':'')
      +'</div>';
    h+='<table class="data-tbl" style="width:100%;border-collapse:collapse;font-size:12px">';
    h+='<thead><tr>'
      +'<th>Market (DM1)</th><th>Products</th>'
      +'<th style="text-align:right">Mkt '+ml+' (K)</th>'
      +'<th style="text-align:right">Zeta '+ml+' (K)</th>'
      +'<th style="text-align:center">Actual %</th>'
      +'<th style="text-align:center">Avg Target %</th>'
      +'<th style="text-align:center">Achievement</th>'
      +'<th style="text-align:center">Gap (pp)</th>'
      +'</tr></thead><tbody>';
    s.detailRows.forEach(function(r){
      var ach2=r.actual!=null&&r.avgTgt!=null&&r.avgTgt>0?r.actual/r.avgTgt*100:null;
      var gap2=r.actual!=null&&r.avgTgt!=null?(r.actual-r.avgTgt)*100:null;
      var lc=ragC(ach2);
      h+='<tr style="border-left:3px solid '+lc+'">';
      h+='<td style="max-width:170px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="'+r.dm1+'">'
        +r.dm1.substring(0,30)+(r.dm1.length>30?'&#8230;':'')
        +(r.isPreComp?' <span style="font-size:10px;background:rgba(16,185,129,.15);color:#10b981;padding:1px 4px;border-radius:3px">&#8776;</span>':'')
        +(r.isNew&&!r.isPreComp?' <span style="font-size:10px;background:rgba(76,110,245,.15);color:var(--acc1);padding:1px 4px;border-radius:3px">NEW</span>':'')
        +'</td>';
      h+='<td style="color:var(--txt2);font-size:11px;max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="'+r.prods.join(', ')+'">'+r.prods.join(', ')+'</td>';
      h+='<td style="text-align:right;color:var(--txt2)">'+(r.mktVal>0?(r.mktVal/1000).toFixed(0):'&#8212;')+'</td>';
      h+='<td style="text-align:right;color:var(--txt2)">'+(r.mktVal>0?(r.zetaVal/1000).toFixed(0):'&#8212;')+'</td>';
      h+='<td style="text-align:center;font-weight:600">'+fP(r.actual)+'</td>';
      h+='<td style="text-align:center">'+fP(r.avgTgt)+'</td>';
      h+='<td style="text-align:center">'+(ach2!=null?'<span style="background:'+lc+'22;color:'+lc+';padding:2px 7px;border-radius:10px;border:1px solid '+lc+'44;font-size:11px">'+ragI(ach2)+' '+ach2.toFixed(0)+'%</span>':'<span style="color:var(--txt3)">&#8212;</span>')+'</td>';
      var gcol=gap2!=null?(gap2>=0?'var(--acc2)':'var(--acc3)'):'var(--txt3)';
      h+='<td style="text-align:center;color:'+gcol+';font-weight:600">'+(gap2!=null?(gap2>=0?'+':'')+gap2.toFixed(1)+' pp':'&#8212;')+'</td>';
      h+='</tr>';
    });
    h+='</tbody></table></div>';
  });

  // Notes
  h+='<div style="padding:12px 16px;background:rgba(93,103,140,.08);border-radius:8px;font-size:12px;color:var(--txt2)">'
    +'<strong>Notes:</strong> Each DM1 market is counted once per BU regardless of how many Zeta products compete in it. '
    +'Avg Target = simple average of product-level DM1 targets within that market. '
    +'Weighted Target at BU level uses actual market size as the weight. '
    +'Markets with &#8776; badge use pre-computed shares from MARKET_ACTUALS and are excluded from the BU blended calculation.'
    +'</div>';

  return h;
}

function taBuToggle(view){
  var pv=document.getElementById('ta-product-view');
  var bv=document.getElementById('ta-bu-view');
  var cv=document.getElementById('ta-corp-view');
  var lv=document.getElementById('ta-line-view');
  var zv=document.getElementById('ta-zeta-view');
  var bp=document.getElementById('ta-btn-product');
  var bb=document.getElementById('ta-btn-bu');
  var bc=document.getElementById('ta-btn-corp');
  var bl=document.getElementById('ta-btn-line');
  var bz=document.getElementById('ta-btn-zeta');
  if(pv) pv.style.display=view==='product'?'':'none';
  if(bv) bv.style.display=view==='bu'?'':'none';
  if(cv) cv.style.display=view==='corp'?'':'none';
  if(lv) lv.style.display=view==='line'?'':'none';
  if(zv) zv.style.display=view==='zeta'?'':'none';
  var tabs={product:bp,bu:bb,corp:bc,line:bl,zeta:bz};
  Object.keys(tabs).forEach(function(k){
    var el=tabs[k];
    if(el){el.style.color=view===k?'var(--acc1)':'var(--txt2)';el.style.borderBottomColor=view===k?'var(--acc1)':'transparent';el.style.fontWeight=view===k?'600':'400';}
  });
}

