  if(b2){b2.style.color=dm==='dm2'?'var(--acc2)':'var(--txt2)';b2.style.borderBottomColor=dm==='dm2'?'var(--acc2)':'transparent';b2.style.fontWeight=dm==='dm2'?'600':'400';}
