// Returns a Set of allowed lookup indices for the given dim, or null (= no restriction)
function getUserAllowedIndices(dim) {
  if(!CURRENT_USER) return null;
  if(dim === 'bu' && CURRENT_USER.bu && CURRENT_USER.bu.length) {
    var s = new Set();
    CURRENT_USER.bu.forEach(function(b){
      var idx = (LOOKUPS.bus||[]).indexOf(b);
      if(idx >= 0) s.add(idx);
    });
    return s.size ? s : null;
  }
  if(dim === 'line' && CURRENT_USER.lines && CURRENT_USER.lines.length) {
    var s2 = new Set();
    CURRENT_USER.lines.forEach(function(l){
      var idx = (LOOKUPS.lines||[]).indexOf(l);
      if(idx >= 0) s2.add(idx);
    });
    return s2.size ? s2 : null;
  }
  if(dim === 'dm1' && CURRENT_USER.dm1s && CURRENT_USER.dm1s.length) {
    var s3 = new Set();
    CURRENT_USER.dm1s.forEach(function(d){
      var dUp = d.toUpperCase().trim();
      var idx = (LOOKUPS.dm1s||[]).findIndex(function(x){return x&&x.toUpperCase().trim()===dUp;});
      if(idx >= 0) s3.add(idx);
    });
    return s3.size ? s3 : null;
  }
  if(dim === 'dm2' && CURRENT_USER.dm1s && CURRENT_USER.dm1s.length) {
    // DM2 mirrors DM1 markets — restrict to same market names in dm2s lookup
    var s4 = new Set();
    CURRENT_USER.dm1s.forEach(function(d){
      var dUp = d.toUpperCase().trim();
      var idx = (LOOKUPS.dm2s||[]).findIndex(function(x){return x&&x.toUpperCase().trim()===dUp;});
      if(idx >= 0) s4.add(idx);
    });
    return s4.size ? s4 : null;
  }
  return null;
}

// Effective BU/Line filter: CURRENT_USER restriction takes priority over STATE filter.
// Returns {hasBu, buSel, hasLine, lineSel} — always use this in analysis functions
// so BU Managers can never see other BUs even with STATE filter empty.
function getEffectiveFilters() {
  var userBu  = getUserAllowedIndices('bu');
  var userLn  = getUserAllowedIndices('line');
  var buSel   = userBu  || STATE.fBuSel;
  var lineSel = userLn  || STATE.fLineSel;
  return {
    hasBu:   buSel.size   > 0,
    buSel:   buSel,
    hasLine: lineSel.size > 0,
    lineSel: lineSel
  };
}

function buildDropdownList(dim) {
  var cfg = MS_CFG[dim];
  if(!cfg) return;
  var items = LOOKUPS[cfg.lookupKey] || [];
  var dd = document.getElementById('f-'+dim+'-dd');
  if(!dd) return;
  var el = document.getElementById('f-'+dim+'-list');
  if(!el) return;
  var sel = STATE[cfg.stateKey];
  if(!sel) return;
  // Add search box if more than 10 items and not already added
  var searchId = 'f-'+dim+'-search';
  if(items.length > 10 && !document.getElementById(searchId)) {
    var sb = document.createElement('div');
    sb.style.cssText = 'padding:6px 10px;border-bottom:1px solid var(--border)';
    sb.innerHTML = '<input id="'+searchId+'" type="text" placeholder="Search..." '
      +'style="width:100%;box-sizing:border-box;background:var(--bg3);border:1px solid var(--border);'
      +'border-radius:4px;padding:4px 8px;font-size:11px;color:var(--txt1);outline:none" '
      +'data-dim="'+dim+'" oninput="filterDropdown(this.dataset.dim,this.value)">';
    dd.insertBefore(sb, el);
  }
  renderDropdownItems(dim, items, sel, el, '', getUserAllowedIndices(dim));
}

function renderDropdownItems(dim, items, sel, el, q, allowedIdx) {
  var html = '';
  var ql = q.toLowerCase();
  var cascade = getCascadeSet(dim); // null if no BU filter active
  var shown = 0;
  for(var i=0;i<items.length;i++) {
    var name = items[i];
    if(!name) continue;
    if(allowedIdx && !allowedIdx.has(i)) continue; // BU/Line Manager restriction
    if(cascade && !cascade.has(i)) continue; // cascade filter
    if(ql && name.toLowerCase().indexOf(ql) < 0) continue;
    shown++;
    var chk = sel.has(i) ? 'checked' : '';
    var safe = name.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    var bg = sel.has(i) ? 'background:rgba(76,110,245,.08);' : '';
    html += '<label style="'+bg+'"><input type="checkbox" data-dim="'+dim+'" class="ms-check-'+dim+'" value="'+i+'" '+chk+' onchange="msCheckChange(this.dataset.dim,this)"> '+safe+'</label>';
  }
  if(!html) html = '<div style="padding:8px 12px;font-size:11px;color:var(--txt3)">No results'+(cascade?' in selected BU':'')+'</div>';
  el.innerHTML = html;
}

function filterDropdown(dim, q) {
  var cfg = MS_CFG[dim]; if(!cfg) return;
  var items = LOOKUPS[cfg.lookupKey]||[];
  var el = document.getElementById('f-'+dim+'-list');
  var sel = STATE[cfg.stateKey];
  if(el && sel) renderDropdownItems(dim, items, sel, el, q, getUserAllowedIndices(dim));
}

