function exportCSV() {
  try {
    var P = LOOKUPS.periods||[], rows=['Period,Corp,DM1,DM2,ATC4,Line,BU,LCV,SU'];
    var cur = getPeriodIndices(STATE.timeRange);
    var df = dimFilter();
    for(var i=0;i<flat.length;i+=10){
      if(!cur.has(flat[i+TI])) continue;
      if(df && !df(flat[i+CI],flat[i+PI],flat[i+TI],flat[i+AI],flat[i+D1I],flat[i+D2I],flat[i+LINEI],flat[i+BUCI])) continue;
      rows.push([
        P[flat[i+TI]]||'',
        (LOOKUPS.corps[flat[i+CI]]||'').replace(/,/g,';'),
        (LOOKUPS.dm1s[flat[i+D1I]]||'').replace(/,/g,';'),
        (LOOKUPS.dm2s[flat[i+D2I]]||'').replace(/,/g,';'),
        (LOOKUPS.atc4s[flat[i+AI]]||'').replace(/,/g,';'),
        (LOOKUPS.lines[flat[i+LINEI]]||'').replace(/,/g,';'),
        (LOOKUPS.bus[flat[i+BUCI]]||'').replace(/,/g,';'),
        flat[i+LI].toFixed(0),
        flat[i+SI].toFixed(0)
      ].join(','));
    }
    var blob = new Blob([rows.join('\n')], {type:'text/csv'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'zeta_iqvia_export.csv';
    a.click();
  } catch(e){ alert('Export error: '+e.message); }
}

// ===================== CASCADE FILTER =====================
// Call after BU or Corp selection changes to restrict other dropdowns
var CASCADE = { dm1s: null, dm2s: null, atc4s: null, lines: null, corps: null };

function buildCascadeFromBU() {
  var buSel = STATE.fBuSel;
  if(!buSel || buSel.size === 0) {
    CASCADE.dm1s = null; CASCADE.dm2s = null;
    CASCADE.atc4s = null; CASCADE.lines = null;
    return;
  }
  var dm1s = new Set(), dm2s = new Set(), atc4s = new Set(), lines = new Set();
  for(var i=0;i<flat.length;i+=10) {
    if(buSel.has(flat[i+9])) { // BUCI=9
      dm1s.add(flat[i+4]);   // D1I=4
      dm2s.add(flat[i+5]);   // D2I=5
      atc4s.add(flat[i+3]);  // AI=3
      lines.add(flat[i+8]);  // LINEI=8
    }
  }
  CASCADE.dm1s = dm1s; CASCADE.dm2s = dm2s;
  CASCADE.atc4s = atc4s; CASCADE.lines = lines;
}

function getCascadeSet(dim) {
  if(dim==='dm1') return CASCADE.dm1s;
  if(dim==='dm2') return CASCADE.dm2s;
  if(dim==='atc4') return CASCADE.atc4s;
  if(dim==='line') return CASCADE.lines;
  return null;
}

// ===================== AI INSIGHT STRIP =====================
function aiInsightStrip(sectionId) {
  try {
    var tr=STATE.timeRange, ml=STATE.metric==='lcv'?'LCV':'SU';
    var cur=getPeriodIndices(tr), prev=getPrevPeriodIndices(tr);
    var df=dimFilter();
    var zIdx=LOOKUPS.corps.findIndex(function(v){return v&&v.toUpperCase().indexOf('ZETA')>=0;});
    function sumF(pidxs,ci){
      var t=0;
      for(var i=0;i<flat.length;i+=10){
        if(!pidxs.has(flat[i+TI])) continue;
        if(ci!==undefined&&flat[i+CI]!==ci) continue;
        if(df&&!df(flat[i+CI],flat[i+PI],flat[i+TI],flat[i+AI],flat[i+D1I],flat[i+D2I],flat[i+LINEI],flat[i+BUCI])) continue;
        t+=STATE.metric==='lcv'?flat[i+LI]:flat[i+SI];
      }
      return t;
    }
    var mC=sumF(cur),mP=sumF(prev);
    var zC=zIdx>=0?sumF(cur,zIdx):0,zP=zIdx>=0?sumF(prev,zIdx):0;
    var mG=mP>0?(mC-mP)/mP:0,zG=zP>0?(zC-zP)/zP:0;
    var sh=mC>0?zC/mC:0,shP=mP>0?zP/mP:0,sd=sh-shP;
    var pills=[],id=sectionId.replace('s-','');
    var mGp=(mG*100).toFixed(1),zGp=(zG*100).toFixed(1);
    var shp=(sh*100).toFixed(1),sdp=(sd*100).toFixed(2);
    var colors={finding:'#4c6ef5',trend:'#36c994',alert:'#ff5c6b',action:'#ff9f45'};
    var rl={mat:'MAT',ytd:'YTD',curr:'Month',all:'All','3m':'3M','6m':'6M'}[tr]||tr;
    if(id==='executive'||id==='corp-intel'||id==='corp-growth'){
      if(mG>0.05) pills.push({t:'trend',s:'Market '+ml+' <b>+'+mGp+'%</b> vs prior.'});
      else if(mG<-0.05) pills.push({t:'alert',s:'Market '+ml+' <b>'+mGp+'%</b> vs prior.'});
      else pills.push({t:'finding',s:'Market stable: '+fmtLCV(mC)+' ('+mGp+'% vs prior).'});
      if(zG>mG+0.02) pills.push({t:'trend',s:'Zeta outgrowing market by <b>'+((zG-mG)*100).toFixed(1)+'pp</b>.'});
      if(zG<mG-0.02) pills.push({t:'alert',s:'Zeta underperforming market by <b>'+((mG-zG)*100).toFixed(1)+'pp</b>.'});
    } else if(id==='dm1-intel'||id==='dm2-intel'||id==='atc4-intel'){
      var dn=id==='dm1-intel'?'DM1':id==='dm2-intel'?'DM2':'ATC4';
      pills.push({t:'finding',s:dn+' market: <b>'+fmtLCV(mC)+'</b> '+ml+'.'});
      if(mG>0.05) pills.push({t:'trend',s:dn+' up <b>+'+mGp+'%</b> vs prior.'});
      if(sd>0.003) pills.push({t:'trend',s:'Zeta share <b>+'+sdp+'pp</b>.'});
      if(sd<-0.003) pills.push({t:'alert',s:'Zeta share <b>'+sdp+'pp</b>.'});
    } else if(id==='product-intel'){
      pills.push({t:'finding',s:'Zeta: <b>'+fmtLCV(zC)+'</b> '+ml+' - '+shp+'% share.'});
      if(zG>0.05) pills.push({t:'trend',s:'Zeta +'+zGp+'% vs prior.'});
      if(zG<-0.05) pills.push({t:'alert',s:'Zeta '+zGp+'% - review portfolio.'});
      pills.push({t:'action',s:'Identify top-growing products and replicate.'});
    } else if(id==='bcg'){
      pills.push({t:'finding',s:'BCG: <b>'+fmtLCV(zC)+'</b> '+ml+'.'});
      pills.push({t:'action',s:'Stars: invest. Cash Cows: harvest. Question Marks: decide. Dogs: exit review.'});
    } else if(id==='zeta-cmd'){
      pills.push({t:'finding',s:'Zeta: <b>'+fmtLCV(zC)+'</b> '+ml+' - <b>'+shp+'%</b> share.'});
      if(sd>0.003) pills.push({t:'trend',s:'Share +'+sdp+'pp.'});
      if(sd<-0.003) pills.push({t:'alert',s:'Share '+sdp+'pp - monitor.'});
    } else if(id==='zeta-market'){
      pills.push({t:'finding',s:'Zeta share: <b>'+shp+'%</b> | '+ml+': <b>'+fmtLCV(zC)+'</b>.'});
      if(zG>mG) pills.push({t:'trend',s:'Zeta growing faster than market (+'+((zG-mG)*100).toFixed(1)+'pp).'});
      else pills.push({t:'alert',s:'Market growing faster than Zeta.'});
    } else if(id==='zeta-comp'){
      pills.push({t:'finding',s:'Market: <b>'+fmtLCV(mC)+'</b> '+ml+'.'});
      if(sh>0.25) pills.push({t:'trend',s:'Zeta dominant at <b>'+shp+'%</b>.'});
      else if(sh<0.10) pills.push({t:'alert',s:'Zeta at <b>'+shp+'%</b> - growth opportunity.'});
      pills.push({t:'action',s:'Target competitor weaknesses for expansion.'});
    } else if(id==='target-achievement'){
      pills.push({t:'finding',s:'Zeta portfolio: <b>'+fmtLCV(zC)+'</b> '+ml+'.'});
      if(zG>0) pills.push({t:'trend',s:'Portfolio +'+zGp+'% vs prior.'});
      else pills.push({t:'alert',s:'Portfolio '+zGp+'% - review declining markets.'});
    } else if(id==='winners'){
      pills.push({t:'finding',s:'Zeta share: <b>'+shp+'%</b> | '+ml+': <b>'+fmtLCV(zC)+'</b>.'});
      if(sd>0) pills.push({t:'trend',s:'Net share gainer (+'+sdp+'pp).'});
      else pills.push({t:'alert',s:'Net share loser ('+sdp+'pp).'});
    } else if(id==='concentration'){
      pills.push({t:'finding',s:'Market: <b>'+fmtLCV(mC)+'</b> | Zeta share: <b>'+shp+'%</b>.'});
      pills.push({t:'action',s:'Sweet spot: Low HHI + High Zeta share. See Guide page for HHI thresholds.'});
    } else if(id==='forecast'){
      pills.push({t:'finding',s:'Market: <b>'+fmtLCV(mC)+'</b> '+ml+'.'});
      if(mG>0) pills.push({t:'trend',s:'Trailing +'+mGp+'% - positive base for forecast.'});
      else pills.push({t:'alert',s:'Trailing '+mGp+'% - contraction reflected in forecasts.'});
    } else {
      pills.push({t:'finding',s:'Market: <b>'+fmtLCV(mC)+'</b> | Zeta: <b>'+fmtLCV(zC)+'</b> ('+shp+'% share) | '+mGp+'% growth.'});
    }
    if(!pills.length) return '';
    var ph=pills.map(function(p){
      var c=colors[p.t]||'#888';
      return '<li><span class="ais-pill" style="background:'+c+'20;color:'+c+';border:1px solid '+c+'40">'+p.t.charAt(0).toUpperCase()+p.t.slice(1)+'</span> '+p.s+'</li>';
    }).join('');
    return '<div class="ai-insight-strip"><div class="ais-header"><span class="ais-icon">AI</span><span class="ais-title">AI Insights</span><span class="ais-ctx">'+rl+'</span></div><ul class="ais-list">'+ph+'</ul></div>';
  } catch(e){ console.warn('aiInsightStrip:',e); return ''; }
}

